import {IonIcon} from '@ionic/react';
import Link, {ThLink} from '../../components/Link';
import ScrollContainer from '../../components/ScrollContainer';
const _not_found = {title: "Unknown", jsx: <><h2 id="talent-not_found-unknown">Unknown</h2>
<p>Unable to find the requested rogue talent.</p>
</>};
const _armor_piercer = {title: "Armor Piercer", addenda: ["sneakattack"], jsx: <><h2 id="talent-armor_piercer-armor-piercer-ex">Armor Piercer (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/monster_hunters_handbook">Monster Hunter's Handbook pg. 9</Link><br/>A rogue with this talent can cause her sneak attacks to pierce through natural armor. When she hits with an attack that deals sneak attack damage, she can forgo one or more of her sneak attack dice to reduce the target's natural armor bonus by that amount (minimum natural armor bonus of +0) until the end of her next turn. A creature cannot be affected by this ability again for 1 minute.</p>
</>};
const _befuddling_strike = {title: "Befuddling Strike", addenda: ["sneakattack"], jsx: <><h2 id="talent-befuddling_strike-befuddling-strike-ex">Befuddling Strike (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 130</Link><br/><strong>Rogue Only:</strong> When the rogue deals sneak attack damage against an opponent, that opponent takes a -2 penalty on attack rolls against the rogue for 1d4 rounds.</p>
</>};
const _bleeding_attack = {title: "Bleeding Attack", addenda: ["sneakattack"], jsx: <><h2 id="talent-bleeding_attack-bleeding-attack-ex">Bleeding Attack (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 68</Link><br/>A rogue with this ability can cause living opponents to bleed by hitting them with a sneak attack. This attack causes the target to take 1 additional point of damage each round for each die of the rogue's sneak attack (e.g., 4d6 equals 4 points of <Link to="/rule/bleed">bleed</Link>). Bleeding creatures take that amount of damage every round at the start of each of their turns. The bleeding can be stopped by a DC 15 Heal check or the application of any effect that heals hit point damage. Bleeding damage from this ability does not stack with itself. Bleeding damage bypasses any damage reduction the creature might possess.</p>
</>};
const _distracting_attack = {title: "Distracting Attack", addenda: ["sneakattack"], jsx: <><h2 id="talent-distracting_attack-distracting-attack-ex">Distracting Attack (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 130</Link><br/>A rogue with this talent can make sneak attacks with subtle flourishes that disorient and distract her enemy. When she hits a creature with a melee attack that deals sneak attack damage, she can forgo the additional damage to cause the creature to become <Link to="/rule/flat_footed">flat-footed</Link> against one target of her choosing until the beginning of her next turn. The rogue cannot designate herself as the creature gaining the benefit of this talent. Creatures with <Link to="/ability/uncanny_dodge">uncanny dodge</Link> are immune to distracting attack.</p>
</>};
const _emboldening_strike = {title: "Emboldening Strike", addenda: ["sneakattack"], jsx: <><h2 id="talent-emboldening_strike-emboldening-strike-ex">Emboldening Strike (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_shadows">Blood of Shadows pg. 8</Link><br/>When a rogue with this talent hits a creature with a melee attack that deals sneak attack damage, she gains a +1 circumstance bonus on saving throws for every 2 sneak attack dice rolled (minimum +1) for 1 round.</p>
</>};
const _extinguishing_strike = {title: "Extinguishing Strike", addenda: ["sneakattack"], jsx: <><h2 id="talent-extinguishing_strike-extinguishing-strike-ex">Extinguishing Strike (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_shadows">Blood of Shadows pg. 8</Link><br/>When a rogue with this talent hits a creature with a melee attack that deals sneak attack damage, any nonmagical light sources worn or carried by the creature (such as lit torches, lanterns, or sunrods) are automatically extinguished. Once per day, the rogue can use this ability to also attempt a dispel check (as per <Link to="/spell/dispel_magic">dispel magic</Link>) against any magical sources of light a target carries, using her rogue level as the caster level.</p>
</>};
const _focusing_attack = {title: "Focusing Attack", addenda: ["sneakattack"], jsx: <><h2 id="talent-focusing_attack-focusing-attack-ex">Focusing Attack (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_shadows">Blood of Shadows pg. 8</Link><br/>When a rogue selects this talent, she must choose the <Link to="/misc/confused">confused</Link>, <Link to="/misc/shaken">shaken</Link>, or <Link to="/misc/sickened">sickened</Link> condition. When the rogue has the selected condition and hits a creature with a melee attack that deals sneak attack damage, the rogue no longer has that condition. A rogue can take this talent up to three times. Each time, she must select a different condition that she is able to remove from herself with a melee attack that deals sneak attack damage. Even if the rogue has taken this talent multiple times, she can remove only a single effect on herself with each melee attack that deals sneak attack damage.</p>
</>};
const _obscuring_blow = {title: "Obscuring Blow", addenda: ["sneakattack"], jsx: <><h2 id="talent-obscuring_blow-obscuring-blow-ex">Obscuring Blow (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_shadows">Blood of Shadows pg. 8</Link><br/>Once per day, the rogue can forgo her potential to deal sneak attack damage to attempt to cloud an opponent's vision. She must declare the use of obscuring blow before she makes the attack. If the attack hits, it does normal damage but, instead of dealing sneak attack damage (and any effect that triggers when the rogue deals sneak attack damage), the target treats all other creatures as if they had <Link to="/rule/concealment">concealment</Link>, suffering a 20% miss chance on all attack rolls for a number of rounds equal to half the rogue's level. A successful Fortitude saving throw reduces this effect to 1 round. The DC of this saving throw is equal to 10 + 1/2 the rogue's level + the rogue's Intelligence modifier.</p>
</>};
const _offensive_defense = {title: "Offensive Defense", addenda: ["sneakattack"], jsx: <><h2 id="talent-offensive_defense-offensive-defense-ex">Offensive Defense (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 130</Link><br/><strong>Rogue Only:</strong> When a rogue with this talent hits a creature with a melee attack that deals sneak attack damage, the rogue gains a +1 dodge bonus to AC for each sneak attack die rolled for 1 round.</p>
</>};
const _powerful_sneak = {title: "Powerful Sneak", addenda: ["sneakattack"], jsx: <><h2 id="talent-powerful_sneak-powerful-sneak-ex">Powerful Sneak (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 131</Link><br/><strong>Rogue Version:</strong> Whenever a rogue with this talent takes a full attack action, she can elect to take a -2 penalty on all attack rolls until the start of her next turn. If an attack during this time is a sneak attack, she treats all 1s on the sneak attack damage dice as 2s.</p>
<p><strong>Unchained Rogue Version:</strong> Whenever a rogue with this talent takes a full attack action, she can elect to take a -2 penalty on all attack rolls until the start of her next turn. If an attack during this time is a sneak attack, she treats all 1s on the sneak attack damage dice as 2s. She can reroll multiple dice, but she can't reroll any individual die more than once per attack.</p>
</>};
const _sacred_sneak_attack = {title: "Sacred Sneak Attack", addenda: ["sneakattack"], jsx: <><h2 id="talent-sacred_sneak_attack-sacred-sneak-attack-su">Sacred Sneak Attack (Su)</h2>
<p><strong>Sources</strong> <Link to="/source/champions_of_purity">Champions of Purity pg. 25</Link><br/><strong>Rogue Only:</strong> When making a sneak attack against an undead creature or evil outsider, the rogue's sneak attack damage is considered good-aligned for the purpose of overcoming damage reduction. Normal weapon damage is unaffected for this attack. A rogue must have a good alignment to select this rogue talent.</p>
</>};
const _sever_alignment = {title: "Sever Alignment", addenda: ["sneakattack"], jsx: <><h2 id="talent-sever_alignment-sever-alignment-su">Sever Alignment (Su)</h2>
<p><strong>Sources</strong> <Link to="/source/distant_realms">Distant Realms pg. 13</Link><br/>When making a sneak attack against an opponent with an alignment subtype, a rogue with this talent can forgo her sneak attack damage to scramble the creature's metaphysical nature. If the attack succeeds, the rogue deals weapon damage as normal, and the target must succeed at a Fortitude save (DC = 10 + half the rogue's level + the rogue's Intelligence modifier) or lose all damage reduction overcome by aligned weapons (such as DR 10/good), lose all regeneration overcome by aligned sources (such as regeneration 10 [good]). The rogue must have the <Link to="/talent/aligned_sneak_attack">aligned sneak attack</Link> talent to select this talent.</p>
</>};
const _shadows_chill = {title: "Shadow's Chill", addenda: ["sneakattack"], jsx: <><h2 id="talent-shadows_chill-shadows-chill-su">Shadow's Chill (Su)</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_shadows">Blood of Shadows pg. 8</Link><br/>When a rogue with this talent hits a creature with a melee weapon that deals sneak attack damage, a number of points of the damage dealt equal to the number of sneak attack dice rolled is cold damage. The remainder of the sneak attack damage and the normal weapon damage are unaffected. The rogue must have cold resistance from a racial trait before selecting this talent.</p>
</>};
const _silencing_strike = {title: "Silencing Strike", addenda: ["sneakattack"], jsx: <><h2 id="talent-silencing_strike-silencing-strike-su">Silencing Strike (Su)</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_guide">Adventurer's Guide pg. 53</Link><br/>Using magic stolen from the <Link to="/rule/hellknights">Hellknights</Link>, Council agents can render foes silent. When a creature is damaged by the rogue's sneak attack, the rogue magically renders the creature mute for 1 round unless it succeeds at a Will save (DC = 10 + half the rogue's level + the rogue's Charisma modifier). Silencing strike can be used a number of times per day equal to half the rogue's level.</p>
</>};
const _slow_reactions = {title: "Slow Reactions", addenda: ["sneakattack"], jsx: <><h2 id="talent-slow_reactions-slow-reactions-ex">Slow Reactions (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 68</Link><br/>Opponents damaged by the rogue's sneak attack can't make attacks of opportunity for 1 round.</p>
</>};
const _sneaky_maneuver = {title: "Sneaky Maneuver", addenda: ["sneakattack"], jsx: <><h2 id="talent-sneaky_maneuver-sneaky-maneuver-ex">Sneaky Maneuver (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/magical_marketplace">Magical Marketplace pg. 26</Link><br/><strong>Rogue Only:</strong> Anytime a rogue with this talent could hit an opponent with a melee sneak attack on her turn, she may take a -2 penalty on her attack roll and attempt a <Link to="/rule/dirty_trick">dirty trick</Link>, <Link to="/rule/disarm">disarm</Link>, <Link to="/rule/steal">steal</Link>, <Link to="/rule/sunder">sunder</Link>, or <Link to="/rule/trip">trip</Link> combat maneuver instead of dealing sneak attack damage. If the attack succeeds, the rogue deals weapon damage as normal and then attempts a combat maneuver check as a swift action (the -2 penalty only applies to the initial attack roll, not the combat maneuver check). This combat maneuver still provokes attacks of opportunity unless the rogue has a feat or ability that allows her to perform it without provoking attacks of opportunity.</p>
</>};
const _stem_the_flow = {title: "Stem the Flow", addenda: ["sneakattack"], jsx: <><h2 id="talent-stem_the_flow-stem-the-flow-su">Stem the Flow (Su)</h2>
<p><strong>Sources</strong> <Link to="/source/champions_of_purity">Champions of Purity pg. 25</Link><br/><strong>Rogue Only:</strong> When making a successful sneak attack against a creature with the ability to <Link to="/ability/channel_energy">channel energy</Link>, the rogue may forgo 3d6 points of sneak attack damage to instead prevent the target from channeling energy for a number of rounds equal to half her rogue level.</p>
</>};
const _underhanded = {title: "Underhanded", addenda: ["sneakattack"], jsx: <><h2 id="talent-underhanded-underhanded-ex">Underhanded (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 70</Link><br/>A rogue with this talent gains a +4 circumstance bonus on all Sleight of Hand checks made to conceal a weapon. Furthermore, if she makes a sneak attack during the surprise round using a concealed weapon that her opponent didn't know about, she does not have to roll sneak attack damage, and the sneak attack deals maximum damage. A rogue can only use the underhanded talent a number of times per day equal to her Charisma modifier (minimum 0).</p>
</>};
const _aligned_sneak_attack = {title: "Aligned Sneak Attack", jsx: <><h2 id="talent-aligned_sneak_attack-aligned-sneak-attack-su">Aligned Sneak Attack (Su)</h2>
<p><strong>Sources</strong> <Link to="/source/distant_realms">Distant Realms pg. 13</Link><br/>When making a sneak attack against a creature that has damage reduction that can be overcome by weapons of a particular alignment (such as DR 5/good), the rogue's attack reduces that damage reduction by an amount equal to the number of sneak attack dice rolled until the end of the rogue's turn.</p>
</>};
const _careful_stab = {title: "Careful Stab", jsx: <><h2 id="talent-careful_stab-careful-stab-ex">Careful Stab (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_guide">Adventurer's Guide pg. 53</Link><br/>When a rogue with this talent reduces a creature to fewer than 0 hp with <Link to="/misc/precision_damage">precision damage</Link>, she can choose to leave that creature at -1 hp and stable.</p>
</>};
const _demand_attention = {title: "Demand Attention", jsx: <><h2 id="talent-demand_attention-demand-attention-ex">Demand Attention (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/cohorts_and_companions">Cohorts and Companions pg. 27</Link><br/><strong>Rogue Only:</strong> The first time each round that you deal sneak attack damage to an opponent, you can forgo sneak attack damage to distract the creature. The target must succeed at a Will save (DC = 10 + the number of sneak attack dice sacrificed + your Charisma modifier) or become distracted until the start of your next turn. Distracted opponents are entirely focused on you, and pay little attention to their surroundings; they are not considered to be observing other characters within 30 feet, allowing them to attempt Stealth checks to hide. A distracted opponent automatically fails Perception checks against creatures more than 30 feet away.</p>
</>};
const _disabling_stunt = {title: "Disabling Stunt", jsx: <><h2 id="talent-disabling_stunt-disabling-stunt-ex">Disabling Stunt (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_combat">Inner Sea Combat pg. 16</Link><br/><strong>Rogue Only:</strong> A rogue with this talent can attempt a Disable Device check against a construct's CMD as a standard action that does not provoke attacks of opportunity. If the check is successful, the rogue can ignore the construct's damage reduction when dealing sneak attack damage for 1 minute. The normal penalties apply to this check if the rogue attempts it without using thieves' tools. A rogue must be trained in Disable Device to select this talent.</p>
</>};
const _fast_getaway = {title: "Fast Getaway", jsx: <><h2 id="talent-fast_getaway-fast-getaway-ex">Fast Getaway (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 130</Link><br/>After successfully making a sneak attack or Sleight of Hand check, a rogue with this talent can spend a move action to take the <Link to="/rule/withdraw">withdraw</Link> action. She can move no more than her speed during this movement.</p>
</>};
const _set_up = {title: "Set-Up", jsx: <><h2 id="talent-set_up-set-up-ex">Set-Up (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/cohorts_and_companions">Cohorts and Companions pg. 27</Link><br/><strong>Rogue Only:</strong> When you successfully hit a target with a sneak attack in melee, you can choose to forgo your additional sneak attack damage to make the target more vulnerable to one of your allies adjacent to it. The first melee attack that ally makes against the target before the beginning of your next turn treats the target as <Link to="/rule/flanked">flanked</Link>, even if your ally is not flanking the target. This has no effect on creatures you could not flank with that ally, even if the ally was properly positioned.</p>
</>};
const _sneak_training = {title: "Sneak Training", jsx: <><h2 id="talent-sneak_training-sneak-training-ex">Sneak Training (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_130_city_in_the_lions_eye">Pathfinder #130: City in the Lion's Eye pg. 76</Link><br/>The rogue counts as having the sneak attack class feature of a rogue of her level for the purpose of meeting prestige class requirements, although this talent doesn't improve the rogue's existing sneak attack ability or grant her the sneak attack class feature if she doesn't already have it. This talent is most useful for rogues that lack the sneak attack class feature, such as those with the <Link to="/arc-rogue/phantom_thief">phantom thief</Link> archetype.</p>
</>};
const _snipers_eye = {title: "Sniper's Eye", jsx: <><h2 id="talent-snipers_eye-snipers-eye-ex">Sniper's Eye (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 131</Link><br/><strong>Rogue Only:</strong> A rogue with this talent can apply her sneak attack damage on ranged attacks targeting foes within 30 feet that benefit from <Link to="/rule/concealment">concealment</Link>. Foes with total concealment are still immune.</p>
</>};
const _surprise_attack = {title: "Surprise Attack", jsx: <><h2 id="talent-surprise_attack-surprise-attack-ex">Surprise Attack (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 69</Link><br/><strong>Rogue Version:</strong> During the surprise round, opponents are always considered <Link to="/rule/flat_footed">flat-footed</Link> to a rogue with this ability, even if they have already acted.</p>
<p><strong>Unchained Rogue Version:</strong> During the surprise round, opponents are always considered flat-footed to a rogue with this ability, even if they have already acted. A rogue with this ability adds 1/2 her rogue level to her sneak attack damage rolls made during the surprise round.</p>
</>};
const _swimming_stunt = {title: "Swimming Stunt", jsx: <><h2 id="talent-swimming_stunt-swimming-stunt-ex">Swimming Stunt (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_combat">Inner Sea Combat pg. 16</Link><br/><strong>Rogue Only:</strong> Once per round, when making an attack against an opponent underwater that qualifies for sneak attack damage, a rogue with this talent can attempt a Swim check as a free action against her opponent's CMD. If the attack and Swim check are both successful, and the attack deals sneak attack damage, the rogue can choose to forgo one or more of her sneak attack dice to reduce the number of total rounds her opponent can <Link to="/rule/suffocation">hold its breath</Link> by 1 round per die. A rogue must be trained in Swim to select this talent.</p>
</>};
const _accurate_poisoner = {title: "Accurate Poisoner", jsx: <><h2 id="talent-accurate_poisoner-accurate-poisoner-ex">Accurate Poisoner (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/potions_and_poisons">Potions and Poisons pg. 13</Link><br/>A rogue with this talent delivers poisons with deadly precision. When the rogue successfully hits an opponent with a poisoned weapon and would deal sneak attack damage, she can forgo the sneak attack damage and increase the poison's potency. If she does, the poison's duration increases by 2 (for example, <Link to="/eq-poison/large_scorpion_venom">large scorpion venom</Link> lasts for 8 rounds instead of 6 rounds, and <Link to="/eq-poison/drow_poison">drow poison</Link> lasts for 4 minutes instead of 2 minutes).</p>
</>};
const _developed_poison_immunity = {title: "Developed Poison Immunity", jsx: <><h2 id="talent-developed_poison_immunity-developed-poison-immunity-ex">Developed Poison Immunity (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_wild">Heroes of the Wild pg. 21</Link><br/>When this talent is taken, select a single animal or plant poison that the rogue has been poisoned with but survived. The rogue automatically succeeds at all Fortitude saves against exposure to the selected poison.</p>
</>};
const _iron_guts = {title: "Iron Guts", jsx: <><h2 id="talent-iron_guts-iron-guts-ex">Iron Guts (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 69</Link><br/>A rogue with this talent has a cast-iron stomach or has trained herself to withstand poisons, especially ingested ones. She gains a +1 bonus on all saves against ingested poisons as well as a +4 bonus on saves against all spells and effects that cause the rogue to be nauseated or sickened.</p>
</>};
const _knockout_queen = {title: "Knockout Queen", jsx: <><h2 id="talent-knockout_queen-knockout-queen-ex">Knockout Queen (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_guide">Adventurer's Guide pg. 53</Link><br/>Sabriune has passed on the secret of swiftly manufacturing <Link to="/eq-poison/drow_poison">drow poison</Link>. Once per day, the rogue can create 1 or more doses of drow poison by spending 25 gp per dose; this process takes 30 minutes of work, regardless of the number of doses she creates. She can create no more than 1 dose for every 3 rogue levels she has (minimum 1 dose). Creating drow poison in this way does not require a skill check, but the created poison spoils if not used within 24 hours. (This spoilage means that selling doses of this poison for a profit to unsuspecting merchants might well result in unwanted repercussions and reprisals!)</p>
</>};
const _lasting_poison = {title: "Lasting Poison", jsx: <><h2 id="talent-lasting_poison-lasting-poison-ex">Lasting Poison (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 131</Link><br/><strong>Rogue Version:</strong> A rogue with this talent can apply poison to a weapon in such a way that it is effective for two successful attacks instead of one. The poison has a reduced effect, however, and saves made against the poison receive a +2 circumstance bonus. Applying poison in this way requires a full-round action, or a standard action if the rogue has the <Link to="/talent/swift_poison">swift poison</Link> talent.</p>
<p><strong>Unchained Rogue Version:</strong> A rogue with this talent can apply poison to a weapon in such a way that it is effective for a number of successful attacks equal to her Dexterity modifier (minimum two) instead of one. This poison has a reduced effect, however, and saves made against the poison gain a +2 circumstance bonus. Applying poison in this way is a full-round action, or a standard action if the rogue has the <em>swift poison</em> rogue talent.</p>
</>};
const _lingering_poison = {title: "Lingering Poison", jsx: <><h2 id="talent-lingering_poison-lingering-poison-ex">Lingering Poison (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/potions_and_poisons">Potions and Poisons pg. 13</Link><br/>A rogue with this talent can have a poison remain inert until a later time. When she delivers a contact or injury poison, instead of the poison's normal onset time, the rogue can delay the poison's effects until up to 1 day from when it is delivered (minimum 1 round). The delayed poison can be detected as normal by spells such as <Link to="/spell/detect_poison">detect poison</Link> and similar abilities.</p>
</>};
const _poison_use = {title: "Poison Use", jsx: <><h2 id="talent-poison_use-poison-use-ex">Poison Use (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_shadows">Blood of Shadows pg. 8</Link><br/>The rogue is trained in the use of poison, and can't accidentally poison herself when applying poison to a weapon.</p>
</>};
const _signature_poison = {title: "Signature Poison", jsx: <><h2 id="talent-signature_poison-signature-poison-ex">Signature Poison (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/potions_and_poisons">Potions and Poisons pg. 13</Link><br/>A rogue with this talent chooses one poison (such as <Link to="/eq-poison/bloodroot">bloodroot</Link> or <Link to="/eq-poison/oil_of_taggit">oil of taggit</Link>) as her signature poison. When she uses the chosen poison, the poison's saving throw DC increases by +2. A rogue can take this talent multiple times, each time applying it to a new poison.</p>
</>};
const _suppress_poison = {title: "Suppress Poison", jsx: <><h2 id="talent-suppress_poison-suppress-poison-ex">Suppress Poison (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/potions_and_poisons">Potions and Poisons pg. 13</Link><br/>A rogue with this talent can stave off the effects of a poison. As an immediate action when she fails a saving throw against a poison, the rogue can attempt the saving throw a second time. If she succeeds at this second saving throw, the poison does not affect her for a number of rounds equal to her Constitution modifier (minimum 1 round), but this time it counts against the poison's duration. This talent has no effect on poisons with an onset longer than immediate.</p>
</>};
const _swift_poison = {title: "Swift Poison", jsx: <><h2 id="talent-swift_poison-swift-poison-ex">Swift Poison (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 131</Link><br/>A rogue with this talent can apply poison to a weapon as a move action, instead of a standard action.</p>
</>};
const _toxic_regurgitation = {title: "Toxic Regurgitation", jsx: <><h2 id="talent-toxic_regurgitation-toxic-regurgitation-ex">Toxic Regurgitation (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/potions_and_poisons">Potions and Poisons pg. 13</Link><br/>A rogue with this talent can drink a non-inhaled poison as a standard action and suspend it within her body. She is not affected by the poison while it is suspended within her, and she doesn't need to attempt saving throws against it. She can suspend a poison within herself in this way for a number of hours equal to her Constitution modifier (minimum 1), after which she must immediately expel the poison or be affected by it as normal. At any time while the poison is suspended within her, the rogue can spit up the poison as a ranged touch attack at any creature within 10 feet. This does not provoke attacks of opportunity. On a successful hit, the struck creature is exposed to the poison as if it were a contact poison. The rogue can maintain only a single suspended poison at a time. If she suspends a new poison, any older suspended poison immediately affects her as normal.</p>
</>};
const _deadly_scratch = {title: "Deadly Scratch", jsx: <><h2 id="talent-deadly_scratch-deadly-scratch-ex">Deadly Scratch (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 92</Link><br/><strong>Rogue Only; Catfolk Only:</strong> A <Link to="/race/catfolk">catfolk</Link> rogue with this talent can apply poison to her claws without accidentally poisoning herself. A catfolk rogue must have the cat's claws racial trait and the <Link to="/ability/poison_use">poison use</Link> class feature before taking this talent.</p>
</>};
const _disarming_luck = {title: "Disarming Luck", jsx: <><h2 id="talent-disarming_luck-disarming-luck-ex">Disarming Luck (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 92</Link><br/><strong>Rogue Only; Catfolk Only:</strong> Once per day, when a <Link to="/race/catfolk">catfolk</Link> rogue attempts to disable a device and fails by 5 or more, she can reroll the check as a free action. She must take the result of the reroll, even if it's worse than the original roll.</p>
</>};
const _graceful_faller = {title: "Graceful Faller", jsx: <><h2 id="talent-graceful_faller-graceful-faller-ex">Graceful Faller (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 92</Link><br/><strong>Rogue Only; Catfolk Only:</strong> A <Link to="/race/catfolk">catfolk</Link> rogue with this talent lands on her feet even when she takes lethal damage from a fall. If the catfolk rogue also has the nimble faller racial trait, she takes damage from any fall as if it were 20 feet shorter than it actually is.</p>
</>};
const _nimble_climber_catfolk = {title: "Nimble Climber", jsx: <><h2 id="talent-nimble_climber_catfolk-nimble-climber-ex">Nimble Climber (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 92</Link><br/><strong>Rogue Only; Catfolk Only:</strong> A <Link to="/race/catfolk">catfolk</Link> rogue with this talent gains a +4 bonus on Climb checks. If she has the climber racial trait, she can take 10 on her Climb checks even when in immediate danger or distracted.</p>
</>};
const _single_minded_appraiser = {title: "Single-Minded Appraiser", jsx: <><h2 id="talent-single_minded_appraiser-single-minded-appraiser-ex">Single-Minded Appraiser (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 92</Link><br/><strong>Rogue Only; Catfolk Only:</strong> A <Link to="/race/catfolk">catfolk</Link> rogue with this talent is skilled at determining the value of sparkly things. She can always take 10 when appraising gems and jewelry.</p>
</>};
const _vicious_claws = {title: "Vicious Claws", jsx: <><h2 id="talent-vicious_claws-vicious-claws-ex">Vicious Claws (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 92</Link><br/><strong>Rogue Only; Catfolk Only:</strong> A <Link to="/race/catfolk">catfolk</Link> with this talent uses d8s to roll sneak attack damage instead of d6s, but only when she uses her claws to make the sneak attack. A catfolk rogue must have the cat's claws racial trait before taking this talent.</p>
</>};
const _cloying_shades = {title: "Cloying Shades", jsx: <><h2 id="talent-cloying_shades-cloying-shades-su">Cloying Shades (Su)</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_shadows">Blood of Shadows pg. 7</Link><br/>When a rogue with this talent uses <Link to="/spell/dimension_door">dimension door</Link> as a spell or spell-like ability, including the abundant step or shadow jump class feature, then all creatures adjacent to the rogue at the start and end of her teleportation are <Link to="/rule/entangled">entangled</Link> by grasping shadows for 1 round (although the creatures are not anchored in place). A successful Reflex saving throw negates this effect. The DC of this saving throw is equal to 10 + 1/2 the rogue's level + the rogue's Intelligence or Charisma modifier (whichever is higher). The rogue must have <em>dimension door</em> as a spell or spell-like ability (including the abundant step or shadow jump class feature) before choosing this talent.</p>
</>};
const _extra_earthcraft = {title: "Extra Earthcraft", jsx: <><h2 id="talent-extra_earthcraft-extra-earthcraft">Extra Earthcraft</h2>
<p><strong>Sources</strong> <Link to="/source/elemental_masters_handbook">Elemental Master's Handbook pg. 9</Link><br/>The rogue gains 2 additional earthcraft points each day. The rogue must have the <Link to="/arc-rogue/earthshadow">earthcraft</Link> ability to select this talent.</p>
</>};
const _minor_magic = {title: "Minor Magic", jsx: <><h2 id="talent-minor_magic-minor-magic-sp">Minor Magic (Sp)</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 68</Link><br/>A rogue with this talent gains the ability to cast a 0-level spell from the <Link to="/main/spells_wizard">sorcerer/wizard</Link> spell list. This spell can be cast three times a day as a spell-like ability. The caster level for this ability is equal to the rogue's level. The save DC for this spell is 10 + the rogue's Intelligence modifier. The rogue must have an Intelligence of at least 10 to select this talent.</p>
</>};
const _demon_lantern = {title: "Demon Lantern", jsx: <><h2 id="talent-demon_lantern-demon-lantern-sp">Demon Lantern (Sp)</h2>
<p><strong>Sources</strong> <Link to="/source/the_harrow_handbook">The Harrow Handbook pg. 20</Link><br/><strong>Rogue Only:</strong> Once per day when she casts <Link to="/spell/dancing_lights">dancing lights</Link>, the rogue can conjure a single demon's lantern instead of the usual four lights. A demon lantern acts in all ways as a <Link to="/spell/hypnotic_pattern">hypnotic pattern</Link> spell cast by a wizard, except it also casts light as a <Link to="/eq-misc/torch">torch</Link> and it <Link to="/misc/fascinated">fascinates</Link> only a single target whose Hit Dice do not exceed the rogue's class level. The save DC of this effect is equal to 11 + the rogue's Intelligence modifier. The rogue must have an Intelligence score of at least 11 to select this talent. A rogue must have selected the <Link to="/talent/minor_magic">minor magic</Link> rogue talent and selected <em>dancing lights</em> as her spell of choice or otherwise be able to cast <em>dancing lights</em> before choosing this talent.</p>
</>};
const _gloom_magic = {title: "Gloom Magic", jsx: <><h2 id="talent-gloom_magic-gloom-magic-sp">Gloom Magic (Sp)</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_shadows">Blood of Shadows pg. 8</Link><br/>A rogue with this talent gains the ability to cast <Link to="/spell/darkness">darkness</Link> two times per day as a spell-like ability. The darkness created by this ability does not impair the rogue's vision. The caster level for this ability is equal to the rogue's level. A rogue must have an Intelligence score of at least 12 and the <Link to="/talent/minor_magic">minor magic</Link> rogue talent before choosing this talent.</p>
</>};
const _greater_gloom_magic = {title: "Greater Gloom Magic", jsx: <><h2 id="talent-greater_gloom_magic-greater-gloom-magic-sp">Greater Gloom Magic (Sp)</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_shadows">Blood of Shadows pg. 8</Link><br/>A rogue with this talent gains the ability to cast <Link to="/spell/deeper_darkness">deeper darkness</Link> once each day as a spell-like ability. The darkness created by this ability does not impair the rogue's vision. The caster level for this ability is equal to the rogue's level. A rogue must have an Intelligence score of at least 13 and the <Link to="/talent/gloom_magic">gloom magic</Link> and <Link to="/talent/minor_magic">minor magic</Link> rogue talents before choosing this talent.</p>
</>};
const _innocent_facade = {title: "Innocent Facade", jsx: <><h2 id="talent-innocent_facade-innocent-facade-sp">Innocent Facade (Sp)</h2>
<p><strong>Sources</strong> <Link to="/source/magic_tactics_toolbox">Magic Tactics Toolbox pg. 27</Link><br/>Once per day, a rogue with this talent can use <Link to="/spell/innocence">innocence</Link> as a spell-like ability, using her rogue level as the spell's caster level. A rogue must have the <Link to="/talent/minor_magic">minor magic</Link> talent before selecting this talent.</p>
</>};
const _major_magic = {title: "Major Magic", jsx: <><h2 id="talent-major_magic-major-magic-sp">Major Magic (Sp)</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 68</Link><br/>A rogue with this talent gains the ability to cast a 1st-level spell from the <Link to="/main/spells_sorcerer">sorcerer</Link>/wizard spell list two times a day as a spell-like ability. The caster level for this ability is equal to the rogue's level. The save DC for this spell is 11 + the rogue's Intelligence modifier. The rogue must have an Intelligence of at least 11 to select this talent. A rogue must have the <Link to="/talent/minor_magic">minor magic</Link> rogue talent before choosing this talent.</p>
</>};
const _one_of_those_faces = {title: "One of Those Faces", jsx: <><h2 id="talent-one_of_those_faces-one-of-those-faces-sp">One of Those Faces (Sp)</h2>
<p><strong>Sources</strong> <Link to="/source/spymasters_handbook">Spymaster's Handbook pg. 21</Link><br/>Each day, you can use <Link to="/spell/disguise_self">disguise self</Link> as a spell-like ability for up to 10 minutes per character level. This duration need not be continuous, but it must be used in 10-minute increments. Additionally, once you have used this ability, whenever you use it for the next 24 hours you must take the same alternate appearance.</p>
</>};
const _shadow_duplicate = {title: "Shadow Duplicate", jsx: <><h2 id="talent-shadow_duplicate-shadow-duplicate-sp">Shadow Duplicate (Sp)</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_shadows">Blood of Shadows pg. 8</Link><br/>Once per day as an immediate action when the rogue is hit, the rogue can create a single shadow duplicate of herself, as per <Link to="/spell/mirror_image">mirror image</Link>. The GM randomly determines whether the attack hit the rogue or the shadow duplicate. The shadow duplicate lasts for a number of rounds equal to the rogue's level, or until the shadow duplicate is dispelled or destroyed. This ability does not stack with the <em>mirror image</em> spell. The caster level for this ability is equal to the rogue's level. A rogue can use this ability one additional time per day for every 5 rogue levels she has.</p>
</>};
const _wild_magic = {title: "Wild Magic", jsx: <><h2 id="talent-wild_magic-wild-magic-sp">Wild Magic (Sp)</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_wild">Heroes of the Wild pg. 21</Link><br/>A rogue with this talent gains the ability to cast a 0-level spell from the <Link to="/main/druid_spell">druid spell list</Link>. This spell can be cast three times per day as a spell-like ability. The caster level for this ability is equal to the rogue's level. The save DC for this spell is 10 + the rogue's Wisdom modifier. The rogue must have a Wisdom score of at least 10 to select this talent.</p>
</>};
const _expert_cypher = {title: "Expert Cypher", jsx: <><h2 id="talent-expert_cypher-expert-cypher-ex">Expert Cypher (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/divine_anthology">Divine Anthology pg. 7</Link><br/>A rogue with this ability can attempt a Linguistics check to decipher a single page of text as a full-round action instead of taking 1 minute as normal. In addition, when the rogue attempts a Use Magic Device check to cast a spell from a scroll, she is treated as though she had the minimum score in the appropriate ability score to cast that spell. Finally, the rogue can choose to add her Intelligence modifier to her Use Magic Device skill checks instead of her Charisma modifier.</p>
</>};
const _occult_dungeoneer = {title: "Occult Dungeoneer", jsx: <><h2 id="talent-occult_dungeoneer-occult-dungeoneer-su">Occult Dungeoneer (Su)</h2>
<p><strong>Sources</strong> <Link to="/source/magic_tactics_toolbox">Magic Tactics Toolbox pg. 7</Link><br/>Street thieves in Absalom expect wares to be securely locked, and sometimes it takes high-quality tools and magic training to ensure there's a meal at the end of the day. A rogue with this ability can use spell trigger and spell completion items as if the following spells were on a spell list to which he has access: <Link to="/spell/detect_secret_doors">detect secret doors</Link>, <Link to="/spell/detect_snares_and_pits">detect snares and pits</Link>, <Link to="/spell/knock">knock</Link>, <Link to="/spell/locate_object">locate object</Link>, and <Link to="/spell/obscure_object">obscure object</Link>. If the <Link to="/misc/spell_trigger">spell-trigger</Link> device allows a wielder to apply his own caster level (such as with a staff), the rogue may use his class level as his caster level. The rogue may also use <em>knock</em> as a supernatural ability once per day, using his rogue level as his caster level.</p>
</>};
const _spell_storing = {title: "Spell Storing", jsx: <><h2 id="talent-spell_storing-spell-storing-su">Spell Storing (Su)</h2>
<p><strong>Sources</strong> <Link to="/source/magic_tactics_toolbox">Magic Tactics Toolbox pg. 7</Link><br/>The rogue can store within himself a single targeted harmless spell of up to 2nd level. The spell must have a casting time of 1 standard action. Anytime a spell that meets these conditions is cast on the rogue, and he does not already have a spell stored, he can choose to store it rather than have it take effect immediately. Anytime afterward, as a standard action, the rogue can have the spell take effect (acting in all ways as if it had just been cast on him). A rogue must have 1 rank of Use Magic Device to select this talent.</p>
</>};
const _the_whole_time = {title: "The Whole Time", jsx: <><h2 id="talent-the_whole_time-the-whole-time-su">The Whole Time (Su)</h2>
<p><strong>Sources</strong> <Link to="/source/magic_tactics_toolbox">Magic Tactics Toolbox pg. 7</Link><br/>Mercenaries in the employ of the <Link to="/rule/aspis_consortium">Aspis Consortium</Link> often use <em>wands of invisibility</em> to attack protected targets, then blend into the crowd to escape or disguise the source of the next attack. A rogue with this ability is practiced at attacking from magical concealment. He can use spell trigger and spell completion items as if the following spells were on a spell list to which he has access: <Link to="/spell/greater_invisibility">greater invisibility</Link>, <Link to="/spell/invisibility">invisibility</Link>, and <Link to="/spell/vanish">vanish</Link>.</p>
<p>Additionally, if the rogue becomes visible as a result of a weapon or spell attack, he can sheathe his weapon as a free action and instantly adopt a neutral posture. With a successful Bluff or Disguise check (opposed by witnesses' Sense Motive or Perception checks, whichever is higher), there is no obvious sign that the rogue is the source of the attack (though a lack of any other reasonable candidate can still lead observers to draw the correct conclusion).</p>
</>};
const _aspexias_mysticism = {title: "Aspexia's Mysticism", jsx: <><h2 id="talent-aspexias_mysticism-aspexias-mysticism-ex">Aspexia's Mysticism (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_guide">Adventurer's Guide pg. 53</Link><br/>The rogue has been trained in a minor occult technique. The rogue gains <Link to="/feat/psychic_sensitivity">Psychic Sensitivity</Link> as a bonus feat.</p>
</>};
const _black_market_connections = {title: "Black Market Connections", jsx: <><h2 id="talent-black_market_connections-black-market-connections-ex">Black Market Connections (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 69</Link><br/>A rogue with this talent gains better access to magic items from black market connections. She treats every <Link to="/rule/settlements_and_districts">settlement</Link> as one size greater for the purpose of determining the gp limit of the base value of items for sale, as well as the number of minor, medium, and major magic items for sale in the settlement. If the settlement is already a metropolis, all minor and medium magic items are for sale, as well as 3d8 major magic items. With a successful Diplomacy check, the rogue can treat the settlement as two sizes larger. If the settlement is already a metropolis and she succeeds at the check, all magic items are for sale. If the settlement is already a large city and she succeeds at the check, all minor and medium magic items are for sale, as well as 3d8 major magic items. With a successful check, the rogue can also sell stolen items on the black market. If the check fails by 5 or more, the rogue does something to spook the market, and treats the city as normal for 1 week. Furthermore, those in control of the black market may alert the authorities to the rogue's presence in an act of reprisal for spooking the market or to divert attention away from their illicit activities. The DCs of the checks are by settlement size and are given in the table below.</p>
<ScrollContainer id="talent-black_market_connections--table-0"><table>
<thead>
<tr>
<th>Community Size</th>
<th>DC</th>
</tr>
</thead>
<tbody><tr>
<td>Thorp</td>
<td>10</td>
</tr>
<tr>
<td>Hamlet</td>
<td>12</td>
</tr>
<tr>
<td>Village</td>
<td>15</td>
</tr>
<tr>
<td>Small town</td>
<td>18</td>
</tr>
<tr>
<td>Large town</td>
<td>20</td>
</tr>
<tr>
<td>Small city</td>
<td>25</td>
</tr>
<tr>
<td>Large city</td>
<td>30</td>
</tr>
<tr>
<td>Metropolis</td>
<td>35</td>
</tr>
</tbody></table></ScrollContainer>
</>};
const _bomber = {title: "Bomber", jsx: <><h2 id="talent-bomber-bomber-su">Bomber (Su)</h2>
<p><strong>Sources</strong> <Link to="/source/ranged_tactics_toolbox">Ranged Tactics Toolbox pg. 7</Link><br/><strong>Rogue Only:</strong> A rogue with this talent can make a number of bombs per day equal to her Intelligence modifier (minimum 1). These bombs act as <Link to="/class/alchemist">alchemist's</Link> bombs, except they deal damage equal to the damage dealt by the rogue's <Link to="/ability/sneak_attack">sneak attack</Link> (the rogue doesn't add her Intelligence modifier to this damage).</p>
</>};
const _bombers_discovery = {title: "Bomber's Discovery", jsx: <><h2 id="talent-bombers_discovery-bombers-discovery-su">Bomber's Discovery (Su)</h2>
<p><strong>Sources</strong> <Link to="/source/ranged_tactics_toolbox">Ranged Tactics Toolbox pg. 7</Link><br/><strong>Rogue Only:</strong> A rogue with this talent gains an alchemist's <Link to="/ability/discovery">discovery</Link> that modifies a bomb. A rogue must have the <Link to="/talent/bomber">bomber</Link> rogue talent to select this talent.</p>
</>};
const _eldritch_conduit = {title: "Eldritch Conduit", jsx: <><h2 id="talent-eldritch_conduit-eldritch-conduit-su">Eldritch Conduit (Su)</h2>
<p><strong>Sources</strong> <Link to="/source/magic_tactics_toolbox">Magic Tactics Toolbox pg. 7</Link><br/>Survival in the Mana Wastes between the nations of Nex and Geb can depend heavily on locating sufficient magical equipment, which sometimes involves stealing power from a wand or scroll to power a more necessary one. As a full-round action, a rogue with this talent can use two potions, two wands, or two scrolls. Each item is expended or loses a charge as if used normally. The rogue chooses to gain the magical effect of one, but calculates its effects using the caster level of the other. The rogue must still succeed at a Use Magic Device check to operate scrolls or wands unless some other ability allows him to do so, but makes only one skill check to operate both items.</p>
</>};
const _follow_along = {title: "Follow Along", jsx: <><h2 id="talent-follow_along-follow-along-ex">Follow Along (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_intrigue">Ultimate Intrigue pg. 44</Link><br/>A rogue with this talent is familiar enough with enchantment magic to fool it, using spellcasters' complacency to set them up for a surprise attack. Whenever she succeeds at a saving throw against an enchantment effect, the rogue learns the spell's effect on a failed save, allowing her to play along and pretend to have failed her save. If she does so, the spellcaster does not learn that she succeeded at her saving throw, even if she was the only target, though she must succeed at an opposed Bluff check against a spellcaster's Sense Motive check to determine whether she is under the enchantment's effects. While this ruse is in place, the spellcaster is <Link to="/rule/flat_footed">flat-footed</Link> against the rogue's first attack. If the spellcaster sees the rogue perform (or fail to perform) an action that would be impossible if she were under the enchantment's effect, he automatically discovers her ruse.</p>
</>};
const _grig_jig = {title: "Grig Jig", jsx: <><h2 id="talent-grig_jig-grig-jig-su">Grig Jig (Su)</h2>
<p><strong>Sources</strong> <Link to="/source/the_harrow_handbook">The Harrow Handbook pg. 20</Link><br/><strong>Rogue Only:</strong> Once per day, the rogue can weave a bit of old Varisian magic into her footwork, dancing with an infectious passion that compels another nearby to join in. The rogue can target one humanoid within 30 feet and attempt a Perform (dance) check as a full-round action that does not provoke an attack of opportunity. Her target must succeed at a Will save (DC equal to the rogue's Perform [dance]) or it begins to dance uncontrollably. So long as the rogue continues to spend a full-round action dancing each round, the affected target does so as well. If the target is attacked or otherwise in immediate danger while dancing, the effect ends. Each round on its turn, the target can attempt an Acrobatics or Perform (dance) check or a Will save (target's choice) against the rogue's Perform (dance) check to end the effect. A target who resists the jig can not be affected by the same rogue's jig for 24 hours. The grig jig is a mind-affecting effect. The rogue must have an Intelligence score of at least 12 to select this talent. A rogue can use this ability once per day, plus one additional time per day for every 5 rogue levels she possesses.</p>
</>};
const _scry_slip = {title: "Scry Slip", jsx: <><h2 id="talent-scry_slip-scry-slip-su">Scry Slip (Su)</h2>
<p><strong>Sources</strong> <Link to="/source/magic_tactics_toolbox">Magic Tactics Toolbox pg. 27</Link><br/>Whenever a rogue with this talent is targeted by a scrying effect that allows a Will save, the caster of the divination must succeed at a caster level check (DC = 15 + the rogue's class level). This talent wards the rogue and any objects she is holding or carrying.</p>
</>};
const _scrying_familiarity = {title: "Scrying Familiarity", jsx: <><h2 id="talent-scrying_familiarity-scrying-familiarity-ex">Scrying Familiarity (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/spymasters_handbook">Spymaster's Handbook pg. 22</Link><br/>You are well acquainted with scrying sensors. You can roll twice and take the better result on saving throws against <Link to="/spelldef/scrying">divination (scrying)</Link> spells and effects, on Perception checks to notice scrying sensors, and on caster level checks to overcome spell resistance when you use a scrying spell or effect. If you notice a magical sensor, you can attempt a Stealth check opposed by the caster's caster level check to avoid being detected by the sensor.</p>
</>};
const _shades_of_gray = {title: "Shades of Gray", jsx: <><h2 id="talent-shades_of_gray-shades-of-gray-ex">Shades of Gray (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_intrigue">Ultimate Intrigue pg. 44</Link><br/>A rogue with this talent uses mental and emotional tricks to protect herself from attempts to discern her alignment. This offers her the benefits of <Link to="/spell/undetectable_alignment">undetectable alignment</Link> whenever she chooses, though she must be conscious to maintain the effect.</p>
</>};
const _umbral_gear = {title: "Umbral Gear", jsx: <><h2 id="talent-umbral_gear-umbral-gear-su">Umbral Gear (Su)</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_shadows">Blood of Shadows pg. 8</Link><br/>As a standard action while in an area of <Link to="/rule/dim_light">dim light</Link> or darkness, a rogue with this talent can coalesce wisps of shadow into a quasi-real, functional item. The rogue must choose whether to make a crowbar, 50 feet of silk rope, a glass cutter, a light melee weapon with which she is proficient, a reversible cloak, thieves' tools, or a wire saw; the GM may allow other similar items. The rogue can use such items for a number of minutes per day equal to 10 plus her rogue level. This duration does not need to be consecutive, but it must be used in 1-minute increments.</p>
<p>An item created with this ability remains until the rogue is no longer touching it, or until the rogue runs out of duration for this talent, at which time it dissolves. A rogue can select this talent more than once, gaining an additional 10 minutes of duration each time this talent is selected. If a rogue has selected this talent at least twice, she adds 50 feet of silk rope with a grappling hook, a masterwork light melee weapon with which she is proficient, and masterwork thieves' tools to the list of things she can create.</p>
</>};
const _acrobatic_assist = {title: "Acrobatic Assist", jsx: <><h2 id="talent-acrobatic_assist-acrobatic-assist-ex">Acrobatic Assist (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/cohorts_and_companions">Cohorts and Companions pg. 27</Link><br/><strong>Rogue Only:</strong> You can expend an attack of opportunity to perform an <Link to="/rule/aid_another">aid another</Link> action to assist an adjacent ally's Acrobatics check, so long as he makes the check as part of movement that passes through your space or an adjacent space. Additionally, whenever you use the aid another action to assist an ally in making an Acrobatics check and you succeed, your ally gains a +1 dodge bonus to AC against attacks of opportunity caused when he moves out of or within a threatened area, until the end of his turn.</p>
</>};
const _assault_leader = {title: "Assault Leader", jsx: <><h2 id="talent-assault_leader-assault-leader-ex">Assault Leader (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 130</Link><br/>Once per day, when the rogue misses with an attack on a flanked opponent, she can designate a single ally who is also flanking the target that her attack missed. That ally can make a single melee attack against the opponent as an immediate action.</p>
</>};
const _got_your_back = {title: "Got Your Back", jsx: <><h2 id="talent-got_your_back-got-your-back-ex">Got Your Back (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/cohorts_and_companions">Cohorts and Companions pg. 27</Link><br/><strong>Rogue Only:</strong> Once per round as an immediate action, you may expend an attack of opportunity to attempt an <Link to="/rule/aid_another_2">aid another</Link> check to improve an ally's attack. You and your ally must both be flanking the same opponent. This counts as an attack of opportunity.</p>
</>};
const _heads_up = {title: "Heads Up", jsx: <><h2 id="talent-heads_up-heads-up-ex">Heads Up (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/cohorts_and_companions">Cohorts and Companions pg. 27</Link><br/><strong>Rogue Only:</strong> When you make a Perception check, as an immediate or swift action you can allow one adjacent ally to act as if they had also made a Perception check with the same result.</p>
</>};
const _sacrifice_self = {title: "Sacrifice Self", jsx: <><h2 id="talent-sacrifice_self-sacrifice-self-ex">Sacrifice Self (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/champions_of_purity">Champions of Purity pg. 25</Link><br/><strong>Rogue Only:</strong> A rogue who makes a successful Reflex save against an area effect can ignore the benefits of her <Link to="/ability/evasion">evasion</Link> ability to shield an adjacent ally against the effect, essentially halving the damage that ally would normally take. A rogue with <Link to="/talent/improved_evasion">improved evasion</Link> can attempt a secondary save against her ally's damage. If the save is successful, neither she nor her ally takes any damage. A rogue must have evasion in order to select this talent, and she must have improved evasion to benefit from the secondary effect.</p>
</>};
const _shove_aside = {title: "Shove Aside", jsx: <><h2 id="talent-shove_aside-shove-aside-ex">Shove Aside (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/cohorts_and_companions">Cohorts and Companions pg. 27</Link><br/><strong>Rogue Only:</strong> When you and an adjacent ally are both in the area of an attack that requires a saving throw, you can take a -4 penalty on your saving throw to grant your ally a +4 bonus on his saving throw. You lose the <Link to="/ability/evasion">evasion</Link> ability against this attack. If you have <Link to="/talent/improved_evasion">improved evasion</Link>, it is reduced to evasion for this attack instead. A rogue must have evasion to select this rogue talent.</p>
</>};
const _acrobatic_stunt = {title: "Acrobatic Stunt", jsx: <><h2 id="talent-acrobatic_stunt-acrobatic-stunt-ex">Acrobatic Stunt (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_combat">Inner Sea Combat pg. 16</Link><br/><strong>Rogue Only:</strong> Once per day, when flanked by at least two opponents, a rogue with this talent can, as an immediate action when any of the threatening opponents attacks her, attempt an Acrobatics check against the highest CMD of the threatening creatures plus 2 per threatening creature beyond the second. If successful, the rogue may take a 5-foot step in any direction, so long as she remains within the reach of the attacker triggering the movement. The rogue's final position is used to determine whether the attacker benefits from flanking. On a failed check, the rogue falls prone in her original position and the attack resolves as normal (the opponent gains a +4 bonus for attacking a prone target). A rogue may use this ability one additional time per day for every 5 rogue levels she possesses. A rogue must be trained in Acrobatics to select this talent.</p>
</>};
const _ambuscading_grapple = {title: "Ambuscading Grapple", jsx: <><h2 id="talent-ambuscading_grapple-ambuscading-grapple-ex">Ambuscading Grapple (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/monster_hunters_handbook">Monster Hunter's Handbook pg. 9</Link><br/>When a rogue with this talent succeeds at a combat maneuver check to grapple an unaware opponent, she can immediately deal her sneak attack damage to the target. This counts as having hit with a sneak attack for the purpose of other abilities and talents.</p>
</>};
const _card_sharp = {title: "Card Sharp", jsx: <><h2 id="talent-card_sharp-card-sharp-su">Card Sharp (Su)</h2>
<p><strong>Sources</strong> <Link to="/source/the_harrow_handbook">The Harrow Handbook pg. 20</Link><br/><strong>Rogue Only:</strong> The rogue gains <Link to="/feat/deadly_dealer">Deadly Dealer</Link> as a bonus feat, even if she does not meet the prerequisites. Thrown cards are treated as darts, but the rogue cannot imbue cards with additional power unless she has the <Link to="/feat/arcane_strike">Arcane Strike</Link> feat. This talent otherwise functions as the Deadly Dealer feat.</p>
</>};
const _castling = {title: "Castling", jsx: <><h2 id="talent-castling-castling-ex">Castling (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/elemental_masters_handbook">Elemental Master's Handbook pg. 9</Link><br/>The rogue treats soft cover granted by creatures of her size or larger as though it were <Link to="/rule/cover">cover</Link> instead. Cover the rogue gains from this talent does not allow her to attempt Stealth checks.</p>
</>};
const _combat_swipe = {title: "Combat Swipe", jsx: <><h2 id="talent-combat_swipe-combat-swipe">Combat Swipe</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 21</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 130</Link>, <Link to="/source/the_elephant_in_the_room_feat_taxes_in_pathfinder">The Elephant in the Room: Feat Taxes in Pathfinder</Link><br/><strong>Rogue Version:</strong> A rogue who selects this talent gains <Link to="/feat/improved_steal">Improved Steal</Link> as a bonus feat.</p>
<p><strong>Unchained Rogue Version:</strong> A rogue who selects this talent gains Improved Steal as a bonus feat. At 6th level, she is treated as if she met all the prerequisites for <Link to="/feat/greater_steal">Greater Steal</Link> (although she must take the feat as normal).</p>
<div className="sideNoteWrap singular optional elephant"><ScrollContainer id="talent-combat_swipe--table-0"><table><tbody><tr><ThLink scope="row" to="/rule/the_elephant_in_the_room"><IonIcon aria-label="The Elephant in the Room" icon="/icons/elephant.svg" /></ThLink><td><p>This talent does not exist.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _combat_trick = {title: "Combat Trick", jsx: <><h2 id="talent-combat_trick-combat-trick">Combat Trick</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 68</Link><br/>A rogue that selects this talent gains a bonus <Link to="/main/combat_feat">combat feat</Link>.</p>
</>};
const _deft_palm = {title: "Deft Palm", jsx: <><h2 id="talent-deft_palm-deft-palm-ex">Deft Palm (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 69</Link><br/>A rogue with this talent can make a Sleight of Hand check to conceal a weapon while holding it in plain sight, even while she is being observed.</p>
</>};
const _disease_use = {title: "Disease Use", jsx: <><h2 id="talent-disease_use-disease-use">Disease Use</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_moon">Blood of the Moon pg. 19</Link><br/><strong>Rogue Only:</strong> A rogue with this talent can apply filth from garbage, a sewer, a city street, a polluted area, or long-unwashed clothing or fur to a weapon as a standard action. Doing so causes the weapon to inflict <Link to="/disease/filth_fever">filth fever</Link> on its next strike. The rogue does not risk exposure to this disease unless she is damaged by the weapon. After a successful attack with the weapon, the filth is dispersed and must be reapplied.</p>
</>};
const _eerie_disappearance = {title: "Eerie Disappearance", jsx: <><h2 id="talent-eerie_disappearance-eerie-disappearance-ex">Eerie Disappearance (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_streets">Heroes of the Streets pg. 26</Link><br/>As a full-round action, the rogue can move up to her speed. If she successfully reaches a location that offers her cover or concealment, any creature observing her must attempt a Perception check opposed by the rogue's Stealth check. On a failed check, the observer loses track of the rogue and fails to note where she moved to. The rogue does not take a penalty on this Stealth check for moving up to her speed. At the end of her movement, the rogue can attempt an Intimidate check to demoralize all foes within 60 feet who were aware of her at any point during her movement and are unaware of her current location. She rolls the Intimidate check only once and compares her result to the DC for each opponent. The rogue must be at least 6th level to select this talent.</p>
</>};
const _escaping_stunt = {title: "Escaping Stunt", jsx: <><h2 id="talent-escaping_stunt-escaping-stunt-ex">Escaping Stunt (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_combat">Inner Sea Combat pg. 16</Link><br/><strong>Rogue Only:</strong> A rogue with this talent can, as an immediate action, attempt an Escape Artist check in place of a Reflex saving throw against any effect that would impose the <Link to="/rule/entangled">entangled</Link> condition on her. Additionally, once per day when she is the target of a grapple combat maneuver, a rogue with this talent can attempt an Escape Artist check as an immediate action, using the result of the skill check in place of her CMD against that combat maneuver attempt. A rogue can use this second ability one additional time per day for every 5 rogue levels she possesses. A rogue must be trained in Escape Artist to select this talent.</p>
</>};
const _false_attacker = {title: "False Attacker", jsx: <><h2 id="talent-false_attacker-false-attacker-ex">False Attacker (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_streets">Heroes of the Streets pg. 26</Link><br/>Whenever the rogue strikes a foe from hiding, she can attempt a Bluff check as an immediate action (opposed by the target's Sense Motive or Perception check, whichever has a higher bonus) before rolling damage to convince the foe that another creature was the attacker. This Bluff check applies the normal modifiers for convincing a creature of a falsehood, but can be accomplished with just physical trickery (a shared language is not required). If the Bluff is successful, and the rogue maintains concealment or cover, the rogue's stealth does not end.</p>
</>};
const _feint_from_shadows = {title: "Feint from Shadows", jsx: <><h2 id="talent-feint_from_shadows-feint-from-shadows-ex">Feint from Shadows (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_shadows">Blood of Shadows pg. 8</Link><br/>A rogue with this talent can <Link to="/skill/feint">feint</Link> in combat using a ranged weapon against a target within 30 feet and cause the opponent to lose his Dexterity modifier against her next melee or ranged attack. The rogue must have <Link to="/rule/concealment">concealment</Link> (but not full concealment) from the target of the feint.</p>
</>};
const _finesse_rogue = {title: "Finesse Rogue", jsx: <><h2 id="talent-finesse_rogue-finesse-rogue">Finesse Rogue</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 68</Link><br/><strong>Rogue Only:</strong> A rogue that selects this talent gains <Link to="/feat/weapon_finesse">Weapon Finesse</Link> as a bonus feat.</p>
</>};
const _firearm_training = {title: "Firearm Training", jsx: <><h2 id="talent-firearm_training-firearm-training-ex">Firearm Training (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 69</Link><br/>A rogue with this talent gains <Link to="/feat/exotic_weapon_proficiency">Exotic Weapon Proficiency</Link> (firearms).</p>
</>};
const _grit = {title: "Grit", jsx: <><h2 id="talent-grit-grit-ex">Grit (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 69</Link><br/>A rogue with this talent gains the <Link to="/feat/amateur_gunslinger">Amateur Gunslinger</Link> feat and one <Link to="/main/grit_feat">grit feat</Link> of her choice. She must fulfill the prerequisites of the grit feat in order to choose it. A rogue must have the <Link to="/talent/firearm_training">firearm training</Link> talent before choosing this one.</p>
</>};
const _flying_stunt = {title: "Flying Stunt", jsx: <><h2 id="talent-flying_stunt-flying-stunt-ex">Flying Stunt (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_combat">Inner Sea Combat pg. 16</Link><br/><strong>Rogue Only:</strong> A rogue with this talent can attempt a Fly check against a target's CMD as a swift action when charging from above that target. Success allows the rogue to add an amount damage equal to her Dexterity modifier to the attack's damage. This additional damage is <Link to="/misc/precision_damage">precision damage</Link> and is not multiplied on a critical hit. A creature immune to sneak attacks is immune to this additional damage. A rogue must be trained in Fly to select this talent.</p>
</>};
const _fortified_position = {title: "Fortified Position", jsx: <><h2 id="talent-fortified_position-fortified-position-ex">Fortified Position (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/elemental_masters_handbook">Elemental Master's Handbook pg. 9</Link><br/>Whenever the rogue gains a bonus on Reflex saves due to cover, she gains an equal bonus on Fortitude saves.</p>
</>};
const _maneuvering_dodge = {title: "Maneuvering Dodge", jsx: <><h2 id="talent-maneuvering_dodge-maneuvering-dodge-ex">Maneuvering Dodge (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_intrigue">Inner Sea Intrigue pg. 32</Link><br/>Whenever a foe of the rogue's size or larger misses the rogue with a melee attack, the rogue gains a +2 bonus on any Acrobatics, Climb, Fly, and Swim checks she attempts for 1 round. At 8th level, this bonus increases to +4.</p>
</>};
const _mien_of_despair = {title: "Mien of Despair", jsx: <><h2 id="talent-mien_of_despair-mien-of-despair-su">Mien of Despair (Su)</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_shadows">Blood of Shadows pg. 8</Link><br/>When a rogue with this talent successfully demoralizes an opponent using the Intimidate skill or performs a successful <Link to="/skill/feint">feint</Link> against an opponent, the opponent loses any morale bonuses and cannot benefit from any morale bonuses for 1d4+1 rounds.</p>
</>};
const _positioning_attack = {title: "Positioning Attack", jsx: <><h2 id="talent-positioning_attack-positioning-attack-ex">Positioning Attack (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 131</Link><br/>Once per day, when a rogue with this talent hits a creature with a melee attack, she can move up to 30 feet without provoking attacks of opportunity. The movement must end in a space adjacent to the creature hit with the melee attack.</p>
</>};
const _resiliency = {title: "Resiliency", jsx: <><h2 id="talent-resiliency-resiliency-ex">Resiliency (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 68</Link><br/>Once per day, a rogue with this ability can gain a number of <Link to="/rule/temporary_hit_points">temporary hit points</Link> equal to the rogue's level. Activating this ability is an immediate action that can only be performed when she is brought to below 0 hit points. This ability can be used to prevent her from dying. These temporary hit points last for 1 minute. If the rogue's hit points drop below 0 due to the loss of these temporary hit points, she falls unconscious and is <Link to="/misc/dying">dying</Link> as normal.</p>
</>};
const _rogue_crawl = {title: "Rogue Crawl", jsx: <><h2 id="talent-rogue_crawl-rogue-crawl-ex">Rogue Crawl (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 68</Link><br/><strong>Rogue Version:</strong> While <Link to="/rule/prone">prone</Link>, a rogue with this ability can move at half speed. This movement provokes attacks of opportunity as normal. A rogue with this talent can take a 5-foot step while crawling.</p>
<p><strong>Unchained Rogue Version:</strong> While prone, a rogue with this ability can move at half speed. This movement provokes attacks of opportunity as normal. A rogue with this talent can take a 5-foot step while crawling and she reduces her attack roll and AC penalties for being prone by 2.</p>
</>};
const _sleight_of_hand_stunt = {title: "Sleight of Hand Stunt", jsx: <><h2 id="talent-sleight_of_hand_stunt-sleight-of-hand-stunt-ex">Sleight of Hand Stunt (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_combat">Inner Sea Combat pg. 16</Link><br/><strong>Rogue Only:</strong> In place of an attack of opportunity, a rogue with this talent can attempt a Sleight of Hand check against the CMD of an opponent that provokes an attack of opportunity by firing a projectile weapon while threatened. If successful, the rogue plucks the ammunition from the provoking weapon, negating the attack. The rogue may use this ability as many times in a round as she could make attacks of opportunity. At the GM's discretion, certain projectile weapons may not be susceptible to this ability, such as siege engines or firearms. A rogue must be trained in Sleight of Hand to select this talent.</p>
</>};
const _snap_shot = {title: "Snap Shot", jsx: <><h2 id="talent-snap_shot-snap-shot-ex">Snap Shot (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 131</Link><br/><strong>Rogue Only:</strong> A rogue with this talent may treat her intitiative roll as a 20 for a surprise round, regardless of her initiative, but she may only take an attack action with a ranged weapon. Her normal initiative roll is used in subsequent rounds. If two or more rogues possess this talent, their initiative determines the order in which they act, but they all go before any other creature. If a rogue is prevented from acting in the surprise round, this talent has no effect.</p>
</>};
const _stand_up = {title: "Stand Up", jsx: <><h2 id="talent-stand_up-stand-up-ex">Stand Up (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 68</Link><br/><strong>Rogue Version:</strong> A rogue with this ability can stand up from a prone position as a free action. This still provokes attacks of opportunity for standing up while threatened by a foe.</p>
<p><strong>Unchained Rogue Version:</strong> A rogue with this ability can stand up from a prone position as a free action. This still provokes attacks of opportunity for standing up while threatened by a foe. A rogue with this ability can stand up from a prone position as a swift action without provoking attacks of opportunity.</p>
</>};
const _stealth_stunt = {title: "Stealth Stunt", jsx: <><h2 id="talent-stealth_stunt-stealth-stunt-ex">Stealth Stunt (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_combat">Inner Sea Combat pg. 16</Link><br/><strong>Rogue Only:</strong> When benefiting from <Link to="/rule/concealment">concealment</Link>, a rogue with this talent can forgo an attack of opportunity to attempt a Stealth check against the provoking opponent's CMD. Success allows the rogue to treat her opponent as <Link to="/rule/flat_footed">flat-footed</Link> against the rogue's first melee attack before the end of her next turn. Using this ability does not count against the rogue's available attacks of opportunity for the round. A rogue must be trained in Stealth to select this talent.</p>
</>};
const _superior_sniper = {title: "Superior Sniper", jsx: <><h2 id="talent-superior_sniper-superior-sniper">Superior Sniper</h2>
<p><strong>Sources</strong> <Link to="/source/magic_tactics_toolbox">Magic Tactics Toolbox pg. 27</Link><br/>A rogue who selects this talent gains <Link to="/feat/expert_sniper">Expert Sniper</Link> as a bonus feat. If she already has this feat, she can instead select any feat that lists Expert Sniper as a prerequisite, as long as she meets the feat's prerequisites.</p>
</>};
const _unbalancing_trick = {title: "Unbalancing Trick", jsx: <><h2 id="talent-unbalancing_trick-unbalancing-trick-ex">Unbalancing Trick (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/elemental_masters_handbook">Elemental Master's Handbook pg. 9</Link><br/>The rogue gains <Link to="/feat/improved_trip">Improved Trip</Link> as a bonus feat, even if she does not meet the prerequisites. At 6th level, she is treated as if she meets all the prerequisites of <Link to="/feat/greater_trip">Greater Trip</Link> (although she must take the feat as normal to gain its benefits).</p>
</>};
const _underhanded_trick = {title: "Underhanded Trick", jsx: <><h2 id="talent-underhanded_trick-underhanded-trick">Underhanded Trick</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_shadows">Blood of Shadows pg. 8</Link><br/>A rogue who selects this talent gains <Link to="/feat/improved_dirty_trick">Improved Dirty Trick</Link> as a bonus feat, even if she does not meet the prerequisites. At 6th level, she is treated as if she meets all the prerequisites for <Link to="/feat/greater_dirty_trick">Greater Dirty Trick</Link> (although she must take the feat as normal). If she succeeds in giving her target the <Link to="/misc/blinded">blinded</Link> condition, the target cannot remove the condition during the first round of blindness.</p>
</>};
const _weapon_training = {title: "Weapon Training", jsx: <><h2 id="talent-weapon_training-weapon-training">Weapon Training</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 69</Link><br/>A rogue that selects this talent gains <Link to="/feat/weapon_focus">Weapon Focus</Link> as a bonus feat.</p>
</>};
const _without_a_trace = {title: "Without a Trace", jsx: <><h2 id="talent-without_a_trace-without-a-trace-ex">Without a Trace (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/ranged_tactics_toolbox">Ranged Tactics Toolbox pg. 7</Link><br/><strong>Rogue Only:</strong> When the rogue successfully uses <Link to="/ability/evasion">evasion</Link> or <Link to="/talent/improved_evasion">improved evasion</Link> to avoid taking damage, she can attempt to hide as an immediate action. The rogue attempts a Stealth check with a -20 penalty, but gains a +1 bonus on her check for every die of damage the avoided attack would have dealt. The rogue can attempt this check even while being observed, as long as she has <Link to="/rule/cover">cover</Link> or <Link to="/rule/concealment">concealment</Link> or an ability that allows her to use the Stealth skill while being observed without cover or concealment.</p>
</>};
const _canny_observer = {title: "Canny Observer", jsx: <><h2 id="talent-canny_observer-canny-observer-ex">Canny Observer (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 130</Link><br/>When a rogue with this talent makes a Perception check to hear the details of a conversation or to find concealed or secret objects (including doors and traps), she gains a +4 bonus.</p>
</>};
const _cunning_trigger = {title: "Cunning Trigger", jsx: <><h2 id="talent-cunning_trigger-cunning-trigger-ex">Cunning Trigger (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 130</Link><br/>A rogue with this talent can use a swift action to set off any trap within 30 feet that she constructed.</p>
</>};
const _quick_trapsmith = {title: "Quick Trapsmith", jsx: <><h2 id="talent-quick_trapsmith-quick-trapsmith-ex">Quick Trapsmith (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 131</Link><br/>As a full-round action, a rogue with this talent can set a simple trap with a CR no greater than 1/2 her rogue level. To do this, she must purchase the components, spend the required time constructing the trap in advance, and have its components at hand. The type of trap that can be constructed in this way is subject to GM discretion.</p>
</>};
const _trap_spotter = {title: "Trap Spotter", jsx: <><h2 id="talent-trap_spotter-trap-spotter-ex">Trap Spotter (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 69</Link><br/>Whenever a rogue with this talent comes within 10 feet of a trap, she receives an immediate Perception skill check to notice the trap. This check should be made in secret by the GM.</p>
</>};
const _fast_picks = {title: "Fast Picks", jsx: <><h2 id="talent-fast_picks-fast-picks-ex">Fast Picks (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 130</Link><br/><strong>Rogue Only:</strong> A rogue with this talent can use the <Link to="/skill/disable_device">Disable Device</Link> skill to attempt to open a lock as a standard action instead of a full-round action.</p>
</>};
const _hairpin_trick = {title: "Hairpin Trick", jsx: <><h2 id="talent-hairpin_trick-hairpin-trick-ex">Hairpin Trick (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_guide">Adventurer's Guide pg. 53</Link><br/>The rogue is skilled at making do with anything she can find. She takes no penalty on <Link to="/skill/disable_device">Disable Device</Link> checks for using improvised tools, and can attempt such checks without any tools at a -4 penalty. She treats all non-improvised thieves' tools as masterwork and doubles the bonus she gets from masterwork thieves' tools from +2 to +4.</p>
</>};
const _last_ditch_effort = {title: "Last Ditch Effort", jsx: <><h2 id="talent-last_ditch_effort-last-ditch-effort">Last Ditch Effort</h2>
<p><strong>Sources</strong> <Link to="/source/people_of_the_sands">People of the Sands pg. 19</Link><br/><strong>Rogue Only:</strong> Once per day, a rogue with this ability who accidentally activates a trap while attempting to disarm it may immediately attempt another Disable Device check to disarm it, albeit at a -5 penalty. The result of the second check is taken even if the result is lower.</p>
</>};
const _papercraft_tools = {title: "Papercraft Tools", jsx: <><h2 id="talent-papercraft_tools-papercraft-tools-ex">Papercraft Tools (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/the_harrow_handbook">The Harrow Handbook pg. 2</Link><br/><strong>Rogue Only:</strong> Traditional thieves' tools might be suspicious, but no guard looks twice at a common deck of cards. So long has the rogue has access to a <Link to="/eq-misc/deck_of_cards">deck of cards</Link>, she can destroy one card to attempt a single <Link to="/skill/disable_device">Disable Device</Link> check as if she had a set of <Link to="/eq-misc/thieves_tools">thieves tools</Link>. If she uses a <Link to="/eq-misc/harrow_deck">harrow card</Link> for this purpose, she can treat the card as a set of masterwork thieves' tools (granting her a +2 circumstance bonus on the Disable Device check), though the card is still destroyed after use.</p>
</>};
const _quick_disable = {title: "Quick Disable", jsx: <><h2 id="talent-quick_disable-quick-disable-ex">Quick Disable (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 68</Link><br/><strong>Rogue Version:</strong> It takes a rogue with this ability half the normal amount of time to disable a trap using the <Link to="/skill/disable_device">Disable Device</Link> skill (minimum 1 round).</p>
<p><strong>Unchained Rogue Version:</strong> It takes a rogue with this ability half the normal amount of time to disable a trap using the Disable Device skill (minimum 1 round). When she uses Disable Device to open a lock that would normally take a full-round action to open, she reduces the duration to a standard action.</p>
</>};
const _camouflage = {title: "Camouflage", jsx: <><h2 id="talent-camouflage-camouflage-ex">Camouflage (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 130</Link><br/>Once per day, a rogue with this talent can craft simple but effective camouflage from the surrounding foliage. The rogue needs 1 minute to prepare the camouflage, but once she does, it is good for the rest of the day or until the rogue fails a saving throw against an area effect spell that deals fire, cold, or acid damage, whichever comes first. The rogue gains a +4 bonus on Stealth checks while within terrain that matches the foliage used to make the camouflage. This ability cannot be used in areas without natural foliage.</p>
</>};
const _charmer = {title: "Charmer", jsx: <><h2 id="talent-charmer-charmer-ex">Charmer (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 130</Link><br/><strong>Rogue Only:</strong> Once per day, the rogue can roll two dice while making a Diplomacy check, and take the better result. She must choose to use this talent before making the Diplomacy check. A rogue can use this ability one additional time per day for every 5 rogue levels she possesses.</p>
</>};
const _coax_information = {title: "Coax Information", jsx: <><h2 id="talent-coax_information-coax-information-ex">Coax Information (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 1</Link>, <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 21</Link><br/><strong>Rogue Version:</strong> A rogue with this talent can use Bluff or Diplomacy in place of Intimidate to force an opponent to act friendly toward her.</p>
<p><strong>Unchained Rogue Version:</strong> A rogue with this talent can use Bluff or Diplomacy in place of Intimidate to force an opponent to act friendly toward her. When the duration of the attitude shift ends, that opponents' attitude toward the rogue returns to its previous level, rather than dropping one level.</p>
</>};
const _convincing_lie = {title: "Convincing Lie", jsx: <><h2 id="talent-convincing_lie-convincing-lie-ex">Convincing Lie (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 69</Link><br/><strong>Rogue Only:</strong> When a rogue with this talent lies, she creates fabrications so convincing that others treat them as truth. When a rogue with this talent successfully uses the Bluff skill to convince someone that what she is saying is true, if that individual is questioned later about the statement or story, that person uses the rogue's Bluff skill modifier to convince the questioner, rather than his own. If his Bluff skill modifier is better than the rogue's, the individual can use his own modifier and gain a +2 bonus on any check to convince others of the lie. This effect lasts for a number of days equal to 1/2 the rogue's level + the rogue's Charisma modifier.</p>
</>};
const _dampen_presence = {title: "Dampen Presence", jsx: <><h2 id="talent-dampen_presence-dampen-presence">Dampen Presence</h2>
<p><strong>Sources</strong> <Link to="/source/magic_tactics_toolbox">Magic Tactics Toolbox pg. 27</Link><br/>A rogue who selects this talent gains <Link to="/feat/dampen_presence">Dampen Presence</Link> as a bonus feat. The rogue does not need to meet the feat's prerequisites. The rogue is also considered to have the <Link to="/feat/skill_focus">Skill Focus</Link> (Stealth) feat for the purpose of satisfying the prerequisites of any feat that lists Dampen Presence as a prerequisite.</p>
</>};
const _face_in_the_crowd = {title: "Face in the Crowd", jsx: <><h2 id="talent-face_in_the_crowd-face-in-the-crowd">Face in the Crowd</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_moon">Blood of the Moon pg. 19</Link><br/><strong>Rogue Only:</strong> A rogue with this talent can blend into groups easily. Opposed Perception and Sense Motive checks take a -2 penalty when made against the rogue's Bluff, Disguise, Sleight of Hand, or Stealth checks if she's within 30 feet of at least two non-hostile characters of her apparent creature type. This penalty increases to -4 if she's within 30 feet of at least eight such creatures or is currently in a square occupied by a crowd.</p>
</>};
const _false_friend = {title: "False Friend", jsx: <><h2 id="talent-false_friend-false-friend-ex">False Friend (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 193</Link><br/>A rogue with this talent gains a +4 bonus when making Bluff checks to convince someone she has never met or who doesn't know her well that they are previously acquainted or know each other well.</p>
</>};
const _fast_fingers = {title: "Fast Fingers", jsx: <><h2 id="talent-fast_fingers-fast-fingers-ex">Fast Fingers (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 130</Link><br/><strong>Rogue Only:</strong> Once per day, a rogue with this talent can roll two dice while making a Sleight of Hand check and take the better result. She must choose to use this talent before making the Sleight of Hand check. A rogue can use this ability one additional time per day for every 5 rogue levels she possesses.</p>
</>};
const _fast_stealth = {title: "Fast Stealth", jsx: <><h2 id="talent-fast_stealth-fast-stealth-ex">Fast Stealth (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 68</Link><br/>This ability allows a rogue to move at full speed using the <Link to="/skill/stealth">Stealth</Link> skill without penalty.</p>
</>};
const _honeyed_words = {title: "Honeyed Words", jsx: <><h2 id="talent-honeyed_words-honeyed-words-ex">Honeyed Words (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 131</Link><br/><strong>Rogue Only:</strong> Once per day, the rogue can roll two dice while making a Bluff check, and take the better result. She must choose to use this talent before making the Bluff check. A rogue can use this ability one additional time per day for every 5 rogue levels she possesses.</p>
</>};
const _innocuous_servant = {title: "Innocuous Servant", jsx: <><h2 id="talent-innocuous_servant-innocuous-servant-ex">Innocuous Servant (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_intrigue">Inner Sea Intrigue pg. 32</Link><br/>The rogue is an expert at appearing to be an unimportant servant, be it an attach&eacute;, bodyguard, driver, maid, kitchen assistant, or similar staff member. The rogue gains a +2 bonus on Disguise checks to appear to be a servant, but not to impersonate a particular servant. She also gains a +2 bonus on Bluff checks to lie to maintain this guise. While disguised as a servant, she gains a +2 bonus on Diplomacy checks to gather information among servants. Because she is easily overlooked as a servant, she can gather information from those she serves without asking them questions directly or alerting them to her interest. Doing so takes 1d4 days and requires a successful Bluff check instead of a Diplomacy check. At 8th level, the bonuses granted by this talent increase to +4.</p>
</>};
const _just_a_face_in_the_crowd = {title: "Just a Face in the Crowd", jsx: <><h2 id="talent-just_a_face_in_the_crowd-just-a-face-in-the-crowd-su">Just a Face in the Crowd (Su)</h2>
<p><strong>Sources</strong> <Link to="/source/magic_tactics_toolbox">Magic Tactics Toolbox pg. 7</Link><br/>The rabble-rousers of Galt can blend into a crowd and are able to hide and spot others who appear to be hiding. The rogue gains a bonus equal to half his class level on Disguise and Perception checks when 10 or more creatures of his size are within 30 feet of him.</p>
</>};
const _obfuscate_story = {title: "Obfuscate Story", jsx: <><h2 id="talent-obfuscate_story-obfuscate-story-ex">Obfuscate Story (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 193</Link><br/><strong>Rogue Only:</strong> While another individual attempts to give an account of an event, the rogue makes an opposed Diplomacy check to deftly interject comments or statements over the course of the storytelling that cause the individual to muddle his ability to recall accurate or specific details. If the rogue succeeds, her target remains unaware that the rogue's interjections caused the confusion. However, if she fails, the target is allowed a Sense Motive check (DC equal to the rogue's failed Diplomacy check) to figure out that she made deliberate attempts to confuse the story.</p>
</>};
const _steal_the_story = {title: "Steal the Story", jsx: <><h2 id="talent-steal_the_story-steal-the-story-ex">Steal the Story (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 193</Link><br/><strong>Rogue Only:</strong> After muddling another's account using obfuscate story, the rogue may make another opposed Diplomacy check to alter the details further in order to discredit, insult, or humiliate the target. If the check succeeds, the target takes a penalty on Diplomacy and Intimidate checks against anyone who heard the altered story. This penalty is equal to the rogue's Intelligence, Wisdom, or Charisma bonus (whichever is highest), and lasts until the target is able to repair his reputation or discredit the rogue. The rogue must have the <Link to="/talent/obfuscate_story">obfuscate story</Link> talent to select this talent.</p>
</>};
const _quick_disguise = {title: "Quick Disguise", jsx: <><h2 id="talent-quick_disguise-quick-disguise-ex">Quick Disguise (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 131</Link><br/>A rogue with this talent can use the items at hand and seemingly innocuous material hidden on her person to create startlingly effective disguises, reducing the amount of time it takes to create a disguise using the Disguise skill.</p>
<p>The time needed for the rogue to alter her appearance in this manner is based on the complexity of the disguise, as noted on the following table. The times are cumulative, so if a female rogue wants to disguise herself as a male of a different race, that takes 2 minutes.</p>
<ScrollContainer id="talent-quick_disguise--table-0"><table>
<thead>
<tr>
<th>Disguise</th>
<th>Time</th>
</tr>
</thead>
<tbody><tr>
<td>Minor details only</td>
<td>1 full-round action</td>
</tr>
<tr>
<td>Disguise as a different gender</td>
<td>1 minute</td>
</tr>
<tr>
<td>Disguise as a different race</td>
<td>1 minute</td>
</tr>
<tr>
<td>Disguise as a different age category</td>
<td>1 minute</td>
</tr>
<tr>
<td>Disguise as a different size category</td>
<td>1 minute</td>
</tr>
</tbody></table></ScrollContainer>
</>};
const _rapid_boost = {title: "Rapid Boost", jsx: <><h2 id="talent-rapid_boost-rapid-boost-ex">Rapid Boost (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/the_harrow_handbook">The Harrow Handbook pg. 2</Link><br/>Once per day, the rogue can roll two dice while attempting a Sleight of Hand check and take the better result. She must choose to use this talent before attempting the Sleight of Hand check. A rogue can use this ability one additional time per day for every 5 rogue levels she has.</p>
</>};
const _sczarni_smuggler = {title: "Sczarni Smuggler", jsx: <><h2 id="talent-sczarni_smuggler-sczarni-smuggler-ex">Sczarni Smuggler (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_intrigue">Inner Sea Intrigue pg. 32</Link><br/>The rogue has picked up Sczarni tricks for making masterful forgeries and using bribery to evade trade rules. The rogue needs to learn only the approximate appearance of a document that doesn't require a particular person's signature to accurately forge the document with <Link to="/skill/linguistics">Linguistics</Link> (gaining a +8 bonus on the check to create the forgery, as if she had seen a similar document before). The rogue needs only a small sample of a person's handwriting to make a convincing forgery of great length in that person's handwriting. The rogue can always take 10 on <Link to="/skill/diplomacy">Diplomacy</Link> checks to offer bribes. In addition, the rogue automatically gains an extra advantage at the start of a <Link to="/rule/pursuit">pursuit</Link> in an urban environment.</p>
</>};
const _scavenger = {title: "Scavenger", jsx: <><h2 id="talent-scavenger-scavenger">Scavenger</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_moon">Blood of the Moon pg. 19</Link><br/><strong>Rogue Only:</strong> A rogue with this talent can pick up and stow an object as a swift action instead of two separate move actions. She gains a +2 bonus on Sleight of Hand checks to pick the pockets of creatures that are stunned or disabled.</p>
</>};
const _terrain_mastery = {title: "Terrain Mastery", jsx: <><h2 id="talent-terrain_mastery-terrain-mastery-ex">Terrain Mastery (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 70</Link><br/>A rogue with this talent gains a <Link to="/ability/favored_terrain">favored terrain</Link> as the ranger ability of the same name, though the favored terrain ability does not increase with her level as the ranger's ability does. A rogue can take this ability multiple times, each time applying it to a new terrain.</p>
</>};
const _bardic_pretender = {title: "Bardic Pretender", jsx: <><h2 id="talent-bardic_pretender-bardic-pretender-ex">Bardic Pretender (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_130_city_in_the_lions_eye">Pathfinder #130: City in the Lion's Eye pg. 76</Link><br/>The rogue knows enough about music and performance to survive in a bardic college and can fake what she doesn't know. The rogue qualifies as having the <Link to="/performance/inspire_competence">inspire competence</Link> bardic performance class feature for the purpose of meeting prestige class requirements, although this talent doesn't grant her the bardic performance ability.</p>
</>};
const _certainty = {title: "Certainty", jsx: <><h2 id="talent-certainty-certainty-ex">Certainty (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 21</Link><br/><strong>Unchained Rogue Only:</strong> The rogue chooses one of the skills she selected with rogue's edge. Once per day, the rogue can reroll a skill check she just made with the selected skill and take the better result. She can use this reroll with the selected skill one additional time per day at 10th level and every 5 levels thereafter. A rogue can select this talent multiple times. Each time, the rogue must choose a different skill. A rogue must have the rogue's edge class feature before selecting this talent.</p>
</>};
const _claimed_turf = {title: "Claimed Turf", jsx: <><h2 id="talent-claimed_turf-claimed-turf-ex">Claimed Turf (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_intrigue">Inner Sea Intrigue pg. 32</Link><br/>The rogue is well known in a specific community in which she gains the benefits of renown. She gains the <Link to="/soctalent/renown">renown</Link> vigilante social talent. This community can be an entire settlement or portions of a settlement (such as a particular district or neighborhood), depending on the population as allowed by the renown social talent. Anytime she could select another rogue talent, the rogue can also select from the following list of social talents, using her rogue level as her vigilante level for the purpose meeting of prerequisites: <Link to="/soctalent/celebrity_discount">celebrity discount</Link>, <Link to="/soctalent/celebrity_perks">celebrity perks</Link>, <Link to="/soctalent/gossip_collector">gossip collector</Link>, <Link to="/soctalent/great_renown">great renown</Link>, <Link to="/soctalent/incredible_renown">incredible renown</Link>, <Link to="/soctalent/loyal_aid">loyal aid</Link>, and <Link to="/soctalent/safe_house">safe house</Link>. For the purposes of vigilante social talents, the rogue does not have a vigilante identity and is always considered to be in her social identity.</p>
</>};
const _climbing_stunt = {title: "Climbing Stunt", jsx: <><h2 id="talent-climbing_stunt-climbing-stunt-ex">Climbing Stunt (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_combat">Inner Sea Combat pg. 16</Link><br/><strong>Rogue Only:</strong> A rogue with this talent can take a -10 penalty on a Climb check to move at full speed while climbing. A rogue must be trained in Climb to select this talent.</p>
</>};
const _esoteric_scholar = {title: "Esoteric Scholar", jsx: <><h2 id="talent-esoteric_scholar-esoteric-scholar-ex">Esoteric Scholar (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 69</Link><br/>Once a day, a rogue with this talent may attempt a Knowledge check, even when she is not trained in that Knowledge skill.</p>
</>};
const _expert_leaper = {title: "Expert Leaper", jsx: <><h2 id="talent-expert_leaper-expert-leaper-ex">Expert Leaper (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 21</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 130</Link><br/><strong>Rogue Version:</strong> When making jump checks, the rogue is always considered to have a running start. Also, when the rogue deliberately falls, a DC 15 Acrobatics check allows her to ignore the first 20 feet fallen, instead of the first 10 feet.</p>
<p><strong>Unchained Rogue Version:</strong> When making jump checks, the rogue is always considered to have a running start, and adds her rogue level to the check result. Also, when the rogue deliberately falls, a DC 15 Acrobatics check allows her to ignore the first 20 feet fallen, instead of the first 10 feet. For every 5 by which she exceeds the DC of this check, she can ignore an additional 10 feet of distance fallen.</p>
</>};
const _favored_terrain = {title: "Favored Terrain", jsx: <><h2 id="talent-favored_terrain-favored-terrain-ex">Favored Terrain (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_wild">Heroes of the Wild pg. 21</Link><br/>The rogue selects one terrain from the ranger's <Link to="/ability/favored_terrain">favored terrain</Link> list; she gains this as a favored terrain, as the ranger class feature. If the rogue also has or later takes the <Link to="/talent/hide_in_plain_sight">hide in plain sight</Link> advanced rogue talent, her favored terrain must match a terrain she has selected for that advanced talent. If the rogue has ranger levels, her effective ranger level is equal to her ranger level + 5 for purposes of improving the bonuses from this favored terrain and gaining new favored terrains. A rogue must be at least 5th level to select this talent.</p>
</>};
const _follow_clues = {title: "Follow Clues", jsx: <><h2 id="talent-follow_clues-follow-clues-ex">Follow Clues (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 130</Link><br/>A rogue with this talent can use Perception to follow tracks as per the <Link to="/skill/survival">Survival</Link> skill.</p>
</>};
const _getaway_artist = {title: "Getaway Artist", jsx: <><h2 id="talent-getaway_artist-getaway-artist-ex">Getaway Artist (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 69</Link><br/>A rogue with this talent adds Fly, Handle Animal, and Ride to her list of class skills, and gains a +2 bonus on all driving checks.</p>
</>};
const _graceful_athlete = {title: "Graceful Athlete", jsx: <><h2 id="talent-graceful_athlete-graceful-athlete">Graceful Athlete</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_beast">Blood of the Beast pg. 6</Link><br/>Gain <Link to="/feat/graceful_athlete">Graceful Athlete</Link> as a bonus feat. You must meet the prerequisites for the feat.</p>
</>};
const _green_tongue = {title: "Green Tongue", jsx: <><h2 id="talent-green_tongue-green-tongue-ex">Green Tongue (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_wild">Heroes of the Wild pg. 21</Link><br/>The rogue gains Aklo, Aquan, Auran, Giant, Ignan, Sylvan, or Terran as a bonus language. In addition, the rogue can attempt a DC 15 <Link to="/skill/linguistics">Linguistics</Link> check to communicate basic concepts with magical beasts and monstrous humanoids with which she does not share a common language.</p>
</>};
const _guileful_polyglot = {title: "Guileful Polyglot", jsx: <><h2 id="talent-guileful_polyglot-guileful-polyglot-ex">Guileful Polyglot (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 130</Link><br/><strong>Rogue Only:</strong> A rogue with this talent who has at least one rank in <Link to="/skill/linguistics">Linguistics</Link> gains four additional <Link to="/misc/languages">languages</Link>. A rogue with this talent who does not have any ranks in Linguistics gains two additional languages. If the rogue later gains ranks in Linguistics, she gains two additional languages, to a total of four additional languages above those granted by the Linguistics skill itself.</p>
</>};
const _hard_to_fool = {title: "Hard to Fool", jsx: <><h2 id="talent-hard_to_fool-hard-to-fool-ex">Hard to Fool (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 130</Link><br/><strong>Rogue Only:</strong> Once per day, a rogue with this talent can roll two dice while making a Sense Motive check, and take the better result. She must choose to use this talent before making the Sense Motive check. A rogue can use this ability one additional time per day for every 5 rogue levels she possesses.</p>
</>};
const _hold_breath = {title: "Hold Breath", jsx: <><h2 id="talent-hold_breath-hold-breath-ex">Hold Breath (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 69</Link><br/><strong>Rogue Only:</strong> A rogue with this talent increases the number of rounds she can <Link to="/misc/hold_her_breath">hold her breath</Link> by 2. She can take this talent multiple times.</p>
</>};
const _ki_pool = {title: "Ki Pool", jsx: <><h2 id="talent-ki_pool-ki-pool-ex">Ki Pool (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 69</Link><br/><strong>Rogue Only:</strong> A rogue with this talent gains a small ki pool. This ki pool is similar to a <Link to="/class/ninja">ninja's</Link> ki pool, but the rogue's ki pool does not grant any extra attacks. The rogue gains a number of ki points equal to her Wisdom modifier (minimum 1). These ki points replenish at the start of each day. If she already has a ki pool, or gains a ki pool later, she gains half her Wisdom bonus (minimum 1) as bonus ki points to her ki pool. She can spend a ki point to gain a +10-foot bonus to movement until the end of her turn.</p>
</>};
const _ledge_walker = {title: "Ledge Walker", jsx: <><h2 id="talent-ledge_walker-ledge-walker-ex">Ledge Walker (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 68</Link><br/><strong>Rogue Version:</strong> This ability allows a rogue to move along narrow surfaces at full speed using the Acrobatics skill without penalty. In addition, a rogue with this talent is not <Link to="/rule/flat_footed">flat-footed</Link> when using Acrobatics to move along narrow surfaces.</p>
<p><strong>Unchained Rogue Version:</strong> This ability allows a rogue to move along narrow surfaces at full speed using the Acrobatics skill without penalty. In addition, a rogue with this talent is not flat-footed when using Acrobatics to move along narrow surfaces and retains her Dexterity bonus to AC.</p>
</>};
const _multitalented = {title: "Multitalented", jsx: <><h2 id="talent-multitalented-multitalented-ex">Multitalented (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 22</Link><br/><strong>Unchained Rogue Only:</strong> The rogue can use her rogue talents more often. Once per day, she can use a rogue talent that is normally only usable once per day one additional time. At 10th level and 18th level, she can use this talent one additional time per day (for a maximum total of 3 additional uses of a rogue talent that can normally only be used once per day). The uses of this talent do not have to be spent on the same rogue talent. This ability cannot be used with an advanced talent.</p>
</>};
const _nimble_climber = {title: "Nimble Climber", jsx: <><h2 id="talent-nimble_climber-nimble-climber-ex">Nimble Climber (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 22</Link><br/><strong>Unchained Rogue Only:</strong> Whenever the rogue fails a Climb check by 5 or more, she can attempt a Reflex save (using the same DC as the Climb check) to catch herself and avoid falling.</p>
</>};
const _ninja_trick = {title: "Ninja Trick", jsx: <><h2 id="talent-ninja_trick-ninja-trick-ex">Ninja Trick (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 70</Link><br/>A rogue with this talent can choose a trick from the <Link to="/ability/ninja_tricks">ninja trick</Link> list. The rogue cannot choose a ninja trick with the same name as a rogue talent. The rogue can choose but cannot use talents that require ki points, unless she has a ki pool. A rogue can pick this talent more than once. The rogue cannot choose a ninja trick with the same name as a rogue talent.</p>
</>};
const _peerless_maneuver = {title: "Peerless Maneuver", jsx: <><h2 id="talent-peerless_maneuver-peerless-maneuver-ex">Peerless Maneuver (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 131</Link><br/><strong>Rogue Only:</strong> Once per day, a rogue with this talent can roll two dice while making an Acrobatics check, and take the better result. She must choose to use this talent before making the Acrobatics check. A rogue can use this ability one additional time per day for every 5 rogue levels she possesses.</p>
</>};
const _philologist = {title: "Philologist", jsx: <><h2 id="talent-philologist-philologist">Philologist</h2>
<p><strong>Sources</strong> <Link to="/source/people_of_the_sands">People of the Sands pg. 19</Link><br/><strong>Rogue Only:</strong> A rogue with this talent can reroll any Linguistics skill check made to decipher writing in an unfamiliar language, and never risks drawing a false conclusion from a failed Wisdom check after a failed Linguistics check. A rogue with this talent is allowed only one reroll per inscription, message, or text encountered.</p>
</>};
const _quick_scrounge = {title: "Quick Scrounge", jsx: <><h2 id="talent-quick_scrounge-quick-scrounge">Quick Scrounge</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_moon">Blood of the Moon pg. 19</Link><br/><strong>Rogue Only:</strong> The rogue can search a creature, object, or area in half as much time as normal. If her Perception check would normally require a full-round action or less, it becomes one step shorter along the following progression: full-round action, standard action, move action, swift action, immediate action. This talent has no effect on Perception checks that are attempted as free actions or Perception checks that don't require an action.</p>
</>};
const _rapid_perception = {title: "Rapid Perception", jsx: <><h2 id="talent-rapid_perception-rapid-perception-su">Rapid Perception (Su)</h2>
<p><strong>Sources</strong> <Link to="/source/magic_tactics_toolbox">Magic Tactics Toolbox pg. 27</Link><br/><strong>Rogue Only:</strong> A rogue with this talent can attempt a Perception check to intentionally search for a specific item or creature as a swift action instead of a move action. If she is intentionally searching for an invisible creature, the creature's bonus on its Stealth check from its invisibility is halved.</p>
</>};
const _riding_stunt = {title: "Riding Stunt", jsx: <><h2 id="talent-riding_stunt-riding-stunt-ex">Riding Stunt (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_combat">Inner Sea Combat pg. 16</Link><br/><strong>Rogue Only:</strong> A rogue with this talent takes only a -2 penalty on Ride checks when riding a mount bareback instead of the normal -5 penalty. When using the Ride skill to make a mount leap, a rogue with this talent can use her Ride modifier or her mount's jump modifier, whichever is higher, instead of using the lower of the two. A rogue with this talent gains a +5 competence bonus when using the Ride skill to soften a fall from her mount or to perform a fast mount or dismount. Finally, a rogue with this talent can attempt a DC 15 Ride check to recover from a position of cover as a free action instead of as a move action. Failing this check results in the recovery requiring a move action as normal. A rogue must be trained in Ride to select this talent.</p>
</>};
const _rope_master = {title: "Rope Master", jsx: <><h2 id="talent-rope_master-rope-master-ex">Rope Master (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 70</Link><br/>A rogue with this ability can move at her normal speed when using rope on a Climb check, can take 10 when using Acrobatics to move over narrow surfaces even when in danger or distracted, and gains a +4 bonus when determining the DC to escape bonds when she ties up a creature.</p>
</>};
const _strong_impression = {title: "Strong Impression", jsx: <><h2 id="talent-strong_impression-strong-impression">Strong Impression</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 131</Link><br/>A rogue who selects this talent gains <Link to="/feat/intimidating_prowess">Intimidating Prowess</Link> as a bonus feat.</p>
</>};
const _strong_stroke = {title: "Strong Stroke", jsx: <><h2 id="talent-strong_stroke-strong-stroke-ex">Strong Stroke (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 70</Link><br/>A rogue with this talent rolls twice when making Swim checks and takes the better result. If she already rolls twice while making a Swim check because of another ability or effect, she gains a +2 insight bonus on both of those rolls instead. If the rogue is under the effect of a spell or ability that forces her to roll two dice and take the worse result, she only needs to roll 1d20 while making Swim checks.</p>
</>};
const _survivalist = {title: "Survivalist", jsx: <><h2 id="talent-survivalist-survivalist">Survivalist</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 131</Link><br/>A rogue with this talent adds Heal and Survival to her list of class skills.</p>
</>};
const _swift_tracker = {title: "Swift Tracker", jsx: <><h2 id="talent-swift_tracker-swift-tracker-ex">Swift Tracker (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_wild">Heroes of the Wild pg. 21</Link><br/>While following tracks, the rogue can move at her normal speed without penalty while using the Survival skill. In addition, the penalty for moving at up to twice her normal speed while following tracks is reduced to -10.</p>
</>};
const _thrill_of_the_chase = {title: "Thrill of the Chase", jsx: <><h2 id="talent-thrill_of_the_chase-thrill-of-the-chase-ex">Thrill of the Chase (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_intrigue">Inner Sea Intrigue pg. 32</Link><br/>The rogue revels in the thrill and adrenaline rush of a challenging chase. When engaged in <Link to="/rule/chases">a chase</Link> or <Link to="/rule/pursuit">pursuit</Link>, the rogue gains one d20 reroll which she can use at any time after the original roll is made but before the results of the roll are revealed; she must take the second result, even if it is lower. She can use this reroll once per chase or once per day during a pursuit. Additionally, she gains <Link to="/feat/run">Run</Link> as a bonus feat.</p>
</>};
const _wall_scramble = {title: "Wall Scramble", jsx: <><h2 id="talent-wall_scramble-wall-scramble-ex">Wall Scramble (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 70</Link><br/>A rogue with this talent rolls twice when making Climb checks and takes the better of the two rolls. If she already rolls twice while making a Climb check because of another ability or effect, she gains a +2 insight bonus on both of those rolls instead. If the rogue is under the effect of a spell or ability that forces her to roll two dice and take the worse result, she only needs to roll 1d20 while making Climb checks.</p>
</>};
const _confounding_blades = {title: "Confounding Blades", topLink: ["Advanced Rogue Talents","ability/advanced_rogue_talents"], addenda: ["sneakattack"], jsx: <><h2 id="talent-confounding_blades-confounding-blades-ex">Confounding Blades (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 70</Link><br/>When a rogue with this talent hits a creature with a melee weapon that deals sneak attack damage, her target cannot make attacks of opportunity for 1d4+1 rounds. The rogue must have the <Link to="/talent/slow_reactions">slow reactions</Link> rogue talent before she can choose this talent.</p>
</>};
const _crippling_strike = {title: "Crippling Strike", topLink: ["Advanced Rogue Talents","ability/advanced_rogue_talents"], addenda: ["sneakattack"], jsx: <><h2 id="talent-crippling_strike-crippling-strike-ex">Crippling Strike (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 69</Link><br/>A rogue with this ability can sneak attack opponents with such precision that her blows weaken and hamper them. An opponent damaged by one of her sneak attacks also takes 2 points of <Link to="/rule/strength_damage">Strength damage</Link>.</p>
</>};
const _deadly_sneak = {title: "Deadly Sneak", topLink: ["Advanced Rogue Talents","ability/advanced_rogue_talents"], addenda: ["sneakattack"], jsx: <><h2 id="talent-deadly_sneak-deadly-sneak-ex">Deadly Sneak (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 131</Link><br/><strong>Rogue Version:</strong> Whenever a rogue with this talent uses the powerful sneak rogue talent, she treats all 1s and 2s on the sneak attack damage dice as 3s. A rogue must have the <Link to="/talent/powerful_sneak">powerful sneak</Link> rogue talent before choosing this talent.</p>
<p><strong>Unchained Rogue Version:</strong> When a rogue with this talent uses the powerful sneak talent, she rerolls all sneak attack dice that resulted in 1s or 2s. She can reroll multiple dice, but she can't reroll any individual die more than once per attack. A rogue must have the powerful sneak talent before selecting this talent.</p>
</>};
const _dispelling_attack = {title: "Dispelling Attack", topLink: ["Advanced Rogue Talents","ability/advanced_rogue_talents"], addenda: ["sneakattack"], jsx: <><h2 id="talent-dispelling_attack-dispelling-attack-su">Dispelling Attack (Su)</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 70</Link><br/>Opponents that are dealt sneak attack damage by a rogue with this ability are affected by a targeted <Link to="/spell/dispel_magic">dispel magic</Link>, targeting the lowest-level spell effect active on the target. The caster level for this ability is equal to the rogue's level. A rogue must have the <Link to="/talent/major_magic">major magic</Link> rogue talent before choosing dispelling attack.</p>
</>};
const _double_debilitation = {title: "Double Debilitation", topLink: ["Advanced Rogue Talents","ability/advanced_rogue_talents"], addenda: ["sneakattack"], jsx: <><h2 id="talent-double_debilitation-double-debilitation-ex">Double Debilitation (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 24</Link><br/><strong>Unchained Rogue Only:</strong> Whenever the rogue inflicts a penalty against a target using the debilitating injury class feature, she can select two penalties to inflict. The target can never be subject to more than two penalties in this way at one time. If any additional penalties are inflicted, any previous penalties immediately end. Any effect that heals damage to the target negates both of the penalties.</p>
</>};
const _entanglement_of_blades = {title: "Entanglement of Blades", topLink: ["Advanced Rogue Talents","ability/advanced_rogue_talents"], addenda: ["sneakattack"], jsx: <><h2 id="talent-entanglement_of_blades-entanglement-of-blades-ex">Entanglement of Blades (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 131</Link><br/><strong>Rogue Only:</strong> When a rogue with this talent hits a creature with a melee attack that deals sneak attack damage, the target cannot take a 5-foot step until the beginning of the rogue's next turn.</p>
</>};
const _hamstring_strike = {title: "Hamstring Strike", topLink: ["Advanced Rogue Talents","ability/advanced_rogue_talents"], addenda: ["sneakattack"], jsx: <><h2 id="talent-hamstring_strike-hamstring-strike-ex">Hamstring Strike (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/magical_marketplace">Magical Marketplace pg. 26</Link><br/><strong>Rogue Only:</strong> Anytime a rogue with this talent successfully hits an opponent with a sneak attack, she may forgo her sneak attack damage to try to hamstring her opponent. If the attack succeeds, the rogue deals weapon damage as normal, but instead of the rogue dealing sneak attack damage, the target is knocked <Link to="/rule/prone">prone</Link> and is unable to take move actions during its next turn. A successful Fortitude save (DC = 10 + 1/2 the rogue's level + the rogue's Dexterity modifier) negates this effect.</p>
</>};
const _harrow_strike = {title: "Harrow Strike", topLink: ["Advanced Rogue Talents","ability/advanced_rogue_talents"], addenda: ["sneakattack"], jsx: <><h2 id="talent-harrow_strike-harrow-strike-ex">Harrow Strike (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/the_harrow_handbook">The Harrow Handbook pg. 21</Link><br/><strong>Rogue Only:</strong> Once per day while making a sneak attack against a creature, you can draw a random card from a <Link to="/eq-misc/harrow_deck">harrow deck</Link> you own. If your attack hits, instead of dealing sneak attack damage as normal, you deal a number of points of ability damage equal to your number of sneak attack dice. The ability score damaged is the score affiliated with the suit of the harrow card drawn. You can use this ability an additional time per day at 15th level and 20th level.</p>
</>};
const _improved_shadows_chill = {title: "Improved Shadow's Chill", topLink: ["Advanced Rogue Talents","ability/advanced_rogue_talents"], addenda: ["sneakattack"], jsx: <><h2 id="talent-improved_shadows_chill-improved-shadows-chill-su">Improved Shadow's Chill (Su)</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_shadows">Blood of Shadows pg. 9</Link><br/>When a rogue with this talent hits a creature with a melee weapon that deals sneak attack damage, the sneak attack damage is cold damage. Normal weapon damage is unaffected. The rogue must have cold resistance from a racial trait and the <Link to="/talent/shadows_chill">shadow's chill</Link> rogue talent before choosing this talent.</p>
</>};
const _petrifying_strike = {title: "Petrifying Strike", topLink: ["Advanced Rogue Talents","ability/advanced_rogue_talents"], addenda: ["sneakattack"], jsx: <><h2 id="talent-petrifying_strike-petrifying-strike-su">Petrifying Strike (Su)</h2>
<p><strong>Sources</strong> <Link to="/source/elemental_masters_handbook">Elemental Master's Handbook pg. 9</Link><br/>Whenever the rogue damages a creature with one of her sneak attacks, she also deals 2 points of <Link to="/rule/dexterity_damage">Dexterity damage</Link> to that creature as its body petrifies.</p>
</>};
const _resonating_rumbles = {title: "Resonating Rumbles", topLink: ["Advanced Rogue Talents","ability/advanced_rogue_talents"], addenda: ["sneakattack"], jsx: <><h2 id="talent-resonating_rumbles-resonating-rumbles-su">Resonating Rumbles (Su)</h2>
<p><strong>Sources</strong> <Link to="/source/elemental_masters_handbook">Elemental Master's Handbook pg. 9</Link><br/>When a rogue with this talent makes a successful sneak attack against a creature with <Link to="/umr/tremorsense">tremorsense</Link>, the rogue can subtract 3 dice from her sneak attack damage to prevent the target from using tremorsense for a number of rounds equal to half her rogue level.</p>
</>};
const _aligned_disguise = {title: "Aligned Disguise", topLink: ["Advanced Rogue Talents","ability/advanced_rogue_talents"], jsx: <><h2 id="talent-aligned_disguise-aligned-disguise-sp">Aligned Disguise (Sp)</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_shadows">Blood of Shadows pg. 8</Link><br/>When a rogue with this talent uses the <Link to="/spell/disguise_self">disguise self</Link> spell-like ability, she can also alter her alignment aura to deceive spells that discern alignment (such as <Link to="/spell/detect_evil">detect evil</Link>) for the duration of the disguise self effect. She can choose to detect as any specific alignment, or to detect as no alignment at all. This ability does not protect against spells or effects that cause harm based on alignment. The rogue must have disguise self as a spell-like ability before choosing this talent.</p>
</>};
const _familiar = {title: "Familiar", topLink: ["Advanced Rogue Talents","ability/advanced_rogue_talents"], jsx: <><h2 id="talent-familiar-familiar-ex">Familiar (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 70</Link><br/>A rogue with this talent gains a <Link to="/sidekick/familiar">familiar</Link> as the <Link to="/ability/familiar">familiar</Link> option of the wizard's arcane bond class feature. This ability functions exactly like that part of the class feature, but the rogue's effective wizard level is her rogue level -4. The rogue must have the <Link to="/talent/minor_magic">minor magic</Link> and <Link to="/talent/major_magic">major magic</Link> talents before she can choose this trick.</p>
</>};
const _founders_blessing = {title: "Founders' Blessing", topLink: ["Advanced Rogue Talents","ability/advanced_rogue_talents"], jsx: <><h2 id="talent-founders_blessing-founders-blessing">Founders' Blessing</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_guide">Adventurer's Guide pg. 53</Link><br/>The rogue can call upon the mystical legacies of the Council. Once per day, she can choose a skill in which she has no ranks. After she spends 10 minutes communing with these mystical spirits, they grant her a luck bonus equal to her rogue level with that skill, and she can attempt checks with that skill as if she were trained in its use. The effects of founder's blessing last for 8 hours.</p>
</>};
const _glib_facade = {title: "Glib Facade", topLink: ["Advanced Rogue Talents","ability/advanced_rogue_talents"], jsx: <><h2 id="talent-glib_facade-glib-facade-sp">Glib Facade (Sp)</h2>
<p><strong>Sources</strong> <Link to="/source/magic_tactics_toolbox">Magic Tactics Toolbox pg. 27</Link><br/>Once per day, a rogue with this advanced talent can use <Link to="/spell/glibness">glibness</Link> as a spell-like ability, using her rogue level as the spell's caster level. A rogue must have the <Link to="/talent/innocent_facade">innocent facade</Link> rogue talent before selecting this talent.</p>
</>};
const _hidden_mind = {title: "Hidden Mind", topLink: ["Advanced Rogue Talents","ability/advanced_rogue_talents"], jsx: <><h2 id="talent-hidden_mind-hidden-mind-ex">Hidden Mind (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_intrigue">Ultimate Intrigue pg. 44</Link><br/><strong>Rogue Only:</strong> A rogue with this talent uses various devious techniques, including mental exercises and dusting her clothing with a small amount of lead, to protect herself from divinations, with the same benefits as if she cast <Link to="/spell/nondetection">nondetection</Link> on herself with a caster level equal to her rogue level.</p>
</>};
const _slippery_mind = {title: "Slippery Mind", topLink: ["Advanced Rogue Talents","ability/advanced_rogue_talents"], jsx: <><h2 id="talent-slippery_mind-slippery-mind-ex">Slippery Mind (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 70</Link><br/>This ability represents the rogue's ability to wriggle free from magical effects that would otherwise control or compel her. If a rogue with slippery mind is affected by an enchantment spell or effect and fails her saving throw, she can attempt it again 1 round later at the same DC. She gets only this one extra chance to succeed on her saving throw.</p>
</>};
const _against_the_wall = {title: "Against the Wall", topLink: ["Advanced Rogue Talents","ability/advanced_rogue_talents"], jsx: <><h2 id="talent-against_the_wall-against-the-wall-ex">Against the Wall (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/elemental_masters_handbook">Elemental Master's Handbook pg. 9</Link><br/>A rogue with this talent is considered to be <Link to="/rule/flanking">flanking</Link> any opponent adjacent to a stone wall (whether the stone is worked or unworked).</p>
</>};
const _another_day = {title: "Another Day", topLink: ["Advanced Rogue Talents","ability/advanced_rogue_talents"], jsx: <><h2 id="talent-another_day-another-day-ex">Another Day (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 131</Link><br/>Once per day, when the rogue would be reduced to 0 or fewer hit points by a melee attack, she can take a 5-foot step as an immediate action. If the movement takes her out of the reach of the attack, she takes no damage from the attack. The rogue is <Link to="/misc/staggered">staggered</Link> for 1 round on her next turn.</p>
</>};
const _blinding_strike = {title: "Blinding Strike", topLink: ["Advanced Rogue Talents","ability/advanced_rogue_talents"], jsx: <><h2 id="talent-blinding_strike-blinding-strike">Blinding Strike</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_shadows">Blood of Shadows pg. 9</Link><br/>A rogue who selects this talent gains <Link to="/feat/blinding_critical">Blinding Critical</Link> as a bonus feat, even if she doesn't meet the prerequisites. The rogue must have the <Link to="/talent/obscuring_blow">obscuring blow</Link> rogue talent and be at least 15th level before choosing this talent.</p>
</>};
const _dance_of_disorienting_shadows = {title: "Dance of Disorienting Shadows", topLink: ["Advanced Rogue Talents","ability/advanced_rogue_talents"], jsx: <><h2 id="talent-dance_of_disorienting_shadows-dance-of-disorienting-shadows-ex">Dance of Disorienting Shadows (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_shadows">Blood of Shadows pg. 9</Link><br/>A rogue with this talent can attempt a Perform (dance) check in place of a combat maneuver check when attempting a <Link to="/rule/reposition">reposition</Link> combat maneuver.</p>
</>};
const _deadly_cocktail = {title: "Deadly Cocktail", topLink: ["Advanced Rogue Talents","ability/advanced_rogue_talents"], jsx: <><h2 id="talent-deadly_cocktail-deadly-cocktail-ex">Deadly Cocktail (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 131</Link><br/>A rogue with this talent can apply two doses of poison to a weapon at once. These can be separate poisons, in which case they both affect the target individually, or two doses of the same toxin, in which case the poisons' frequency is extended by 50% and the save DC increases by +2. This talent is an exception to the rule that injury poisons can only be delivered one dose at a time.</p>
</>};
const _defensive_roll = {title: "Defensive Roll", topLink: ["Advanced Rogue Talents","ability/advanced_rogue_talents"], jsx: <><h2 id="talent-defensive_roll-defensive-roll-ex">Defensive Roll (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 69</Link><br/>With this advanced talent, the rogue can roll with a potentially lethal blow to take less damage from it than she otherwise would. Once per day, when she would be reduced to 0 or fewer hit points by damage in combat (from a weapon or other blow, not a spell or special ability), the rogue can attempt to roll with the damage. To use this ability, the rogue must attempt a Reflex saving throw (DC = damage dealt). If the save succeeds, she takes only half damage from the blow; if it fails, she takes full damage. She must be aware of the attack and able to react to it in order to execute her defensive roll&mdash;if she is denied her Dexterity bonus to AC, she can't use this ability. Since this effect would not normally allow a character to make a Reflex save for half damage, the rogue's <Link to="/ability/evasion">evasion</Link> ability does not apply to the defensive roll.</p>
</>};
const _fast_tumble = {title: "Fast Tumble", topLink: ["Advanced Rogue Talents","ability/advanced_rogue_talents"], jsx: <><h2 id="talent-fast_tumble-fast-tumble-ex">Fast Tumble (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 131</Link><br/>When a rogue with this talent uses <Link to="/skill/acrobatics">Acrobatics</Link> to move at full speed through a threatened square without provoking an attack of opportunity, the DC of the Acrobatics check does not increase by 10.</p>
</>};
const _grazing_shot = {title: "Grazing Shot", topLink: ["Advanced Rogue Talents","ability/advanced_rogue_talents"], jsx: <><h2 id="talent-grazing_shot-grazing-shot-ex">Grazing Shot (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/agents_of_evil">Agents of Evil pg. 24</Link><br/>(<Link to="/race/drow">Drow</Link> Only) Particularly deft rogues can strike two foes with one well-placed shot. As a standard action, a rogue with this talent can fire a <Link to="/eq-weapon/hand_crossbow">hand crossbow</Link> at an enemy who is granted cover by another opponent. Make one ranged attack roll and compare the result to each opponent's AC. Each hit deals 1 point of damage. Any special weapon properties or <Link to="/misc/precision_damage">precision damage</Link> apply to only a single target, but any poison applied to the bolt affects all targets struck.</p>
</>};
const _hard_minded = {title: "Hard Minded", topLink: ["Advanced Rogue Talents","ability/advanced_rogue_talents"], jsx: <><h2 id="talent-hard_minded-hard-minded-ex">Hard Minded (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 70</Link><br/>A rogue with this talent is hard to fool with illusions. She automatically receives a save to disbelieve any illusion she can see each round at the start of her turn, even if she hasn't interacted with it. If she fails a saving throw against an illusion that is not to disbelieve, she can attempt to save again again 1 round later at the same DC. She gets only one extra chance to succeed at her saving throw.</p>
</>};
const _hunters_surprise = {title: "Hunter's Surprise", topLink: ["Advanced Rogue Talents","ability/advanced_rogue_talents"], jsx: <><h2 id="talent-hunters_surprise-hunters-surprise-ex">Hunter's Surprise (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 132</Link><br/>Once per day, a rogue with this talent can designate a single enemy she is adjacent to as her prey. Until the end of her next turn, she can add her sneak attack damage to all attacks made against her prey, even if she is not flanking it or it is not flat-footed.</p>
</>};
const _improved_evasion = {title: "Improved Evasion", topLink: ["Advanced Rogue Talents","ability/advanced_rogue_talents"], jsx: <><h2 id="talent-improved_evasion-improved-evasion-ex">Improved Evasion (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 70</Link><br/>This works like <Link to="/ability/evasion">evasion</Link>, except that while the rogue still takes no damage on a successful Reflex saving throw against attacks, she henceforth takes only half damage on a failed save. A <Link to="/misc/helpless">helpless</Link> rogue does not gain the benefit of improved evasion.</p>
</>};
const _knock_out_blow = {title: "Knock-Out Blow", topLink: ["Advanced Rogue Talents","ability/advanced_rogue_talents"], jsx: <><h2 id="talent-knock_out_blow-knock-out-blow-ex">Knock-Out Blow (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 132</Link><br/>Once per day, the rogue can forgo her sneak attack damage to attempt to knock out an opponent. She must declare the use of knock-out blow before she makes the attack. If the attack hits, it does normal damage, but instead of dealing sneak attack damage (and instead of any effect that triggers when the rogue deals sneak attack damage), the target falls <Link to="/misc/unconscious">unconscious</Link> for 1d4 rounds. A successful Fortitude save reduces this effect to <Link to="/misc/staggered">staggered</Link> for 1 round. The DC of this save is equal to 10 + 1/2 the rogue's level + the rogue's Intelligence modifier.</p>
</>};
const _light_walker = {title: "Light Walker", topLink: ["Advanced Rogue Talents","ability/advanced_rogue_talents"], jsx: <><h2 id="talent-light_walker-light-walker-ex">Light Walker (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 24</Link><br/><strong>Unchained Rogue Only:</strong> The rogue can move at full speed through <Link to="/rule/difficult_terrain">difficult terrain</Link> and can take 5-foot steps into difficult terrain. A rogue must have the <Link to="/talent/ledge_walker">ledge walker</Link> rogue talent before choosing light walker.</p>
</>};
const _opportunist = {title: "Opportunist", topLink: ["Advanced Rogue Talents","ability/advanced_rogue_talents"], jsx: <><h2 id="talent-opportunist-opportunist-ex">Opportunist (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 70</Link><br/>Once per round, the rogue can make an attack of opportunity against an opponent who has just been struck for damage in melee by another character. This attack counts as an attack of opportunity for that round. Even a rogue with the <Link to="/feat/combat_reflexes">Combat Reflexes</Link> feat can't use the opportunist ability more than once per round.</p>
</>};
const _quick_shot = {title: "Quick Shot", topLink: ["Advanced Rogue Talents","ability/advanced_rogue_talents"], jsx: <><h2 id="talent-quick_shot-quick-shot-ex">Quick Shot (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 24</Link><br/><strong>Unchained Rogue Only:</strong> Whenever the rogue rolls initiative, she can also make a single attack with a ranged weapon as a swift action. She can use this ability only if she has a weapon in hand and it is loaded (if applicable). If more than one rogue has this talent, their initiative check results determine the order in which they make their attacks. After these attacks are resolved, the round proceeds as normal.</p>
</>};
const _redirect_attack = {title: "Redirect Attack", topLink: ["Advanced Rogue Talents","ability/advanced_rogue_talents"], jsx: <><h2 id="talent-redirect_attack-redirect-attack-ex">Redirect Attack (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 132</Link><br/>Once per day, when a rogue with this talent is hit with a melee attack, she can redirect the attack to strike at an adjacent creature with a free action. The creature targeted must be within melee reach of the attack that hit the rogue, and the creature that made the attack against the rogue must make a new attack roll against the new target.</p>
</>};
const _reflexive_shadow_shield = {title: "Reflexive Shadow Shield", topLink: ["Advanced Rogue Talents","ability/advanced_rogue_talents"], jsx: <><h2 id="talent-reflexive_shadow_shield-reflexive-shadow-shield-su">Reflexive Shadow Shield (Su)</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_shadows">Blood of Shadows pg. 9</Link><br/>Once per day as an immediate action, the rogue can gain an amount of cold resistance or electricity resistance equal to half the rogue's level. This resistance lasts for 1 round. If the rogue has the <em>shadowy resistance</em> racial trait, the cold or electricity resistance stacks with the resistance that trait grants; otherwise, the energy resistance does not stack with any cold or electricity resistance the rogue has. The rogue must have the <Link to="/talent/resiliency">resiliency</Link> rogue talent before choosing this talent.</p>
</>};
const _shrinewalk = {title: "Shrinewalk", topLink: ["Advanced Rogue Talents","ability/advanced_rogue_talents"], jsx: <><h2 id="talent-shrinewalk-shrinewalk-sp">Shrinewalk (Sp)</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_guide">Adventurer's Guide pg. 53</Link><br/>Council agents can walk the mystic paths between Westcrown's shrines. A rogue with shrinewalk can create her own shrine simply by designating an area in any urban region by placing a unique marking or rune on a wall or the ground. This marking is not magical, and if it is defaced or erased, it can no longer be used by the rogue (the marking can be hidden from view without removing its usability, including painting over the marking in question). Once placed, the rogue can use <Link to="/spell/word_of_recall">word of recall</Link> once per day to return to the shrine. A rogue can maintain one shrine at a time; if a new marking is created in a new location, the previous shrine becomes inactive.</p>
</>};
const _stealthy_sniper = {title: "Stealthy Sniper", topLink: ["Advanced Rogue Talents","ability/advanced_rogue_talents"], jsx: <><h2 id="talent-stealthy_sniper-stealthy-sniper-ex">Stealthy Sniper (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 132</Link><br/>When a rogue with this talent uses the <Link to="/skill/stealth">Stealth</Link> skill to snipe, she only suffers a -10 penalty on the Stealth check, instead of -20.</p>
</>};
const _unwitting_ally = {title: "Unwitting Ally", topLink: ["Advanced Rogue Talents","ability/advanced_rogue_talents"], jsx: <><h2 id="talent-unwitting_ally-unwitting-ally-ex">Unwitting Ally (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 71</Link><br/>A rogue with this talent can spend a swift action to attempt to make an opponent act like an ally for purposes of providing a <Link to="/rule/flank">flank</Link> until the beginning of the rogue's next turn. The opponent must be able to hear and see the rogue, and the rogue must succeed at a Bluff check opposed by the opponent's Sense Motive. If the check succeeds, the opponent acts as an ally for the purpose of providing a flank. Whether or not the check succeeds, the rogue cannot use this trick again on the same opponent for the next 24 hours. If the rogue fails the check by 5 or more, she cannot use the unwitting ally ability on any opponent within line of sight of the failed attempt for 24 hours.</p>
</>};
const _weapon_snatcher = {title: "Weapon Snatcher", topLink: ["Advanced Rogue Talents","ability/advanced_rogue_talents"], jsx: <><h2 id="talent-weapon_snatcher-weapon-snatcher-ex">Weapon Snatcher (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 71</Link><br/>A rogue with this talent can make a Sleight of Hand check in place of a combat maneuver check when attempting to <Link to="/rule/disarm">disarm</Link> an opponent.</p>
</>};
const _cutting_edge = {title: "Cutting Edge", topLink: ["Advanced Rogue Talents","ability/advanced_rogue_talents"], jsx: <><h2 id="talent-cutting_edge-cutting-edge-ex">Cutting Edge (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 23</Link><br/><strong>Unchained Rogue Only:</strong> A rogue with this ability immediately selects two additional skills with her rogue's edge ability. She can select this advanced talent multiple times.</p>
</>};
const _feat = {title: "Feat", topLink: ["Advanced Rogue Talents","ability/advanced_rogue_talents"], jsx: <><h2 id="talent-feat-feat">Feat</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 70</Link><br/>A rogue may gain any feat that she qualifies for in place of a rogue talent.</p>
</>};
const _frugal_trapsmith = {title: "Frugal Trapsmith", topLink: ["Advanced Rogue Talents","ability/advanced_rogue_talents"], jsx: <><h2 id="talent-frugal_trapsmith-frugal-trapsmith-ex">Frugal Trapsmith (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 132</Link><br/>When a rogue with this talent constructs a mechanical trap, she only pays 75% of the normal cost.</p>
</>};
const _getaway_master = {title: "Getaway Master", topLink: ["Advanced Rogue Talents","ability/advanced_rogue_talents"], jsx: <><h2 id="talent-getaway_master-getaway-master-ex">Getaway Master (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 70</Link><br/>A rogue with this talent gains a +10 bonus on all drive checks. The rogue must have the <Link to="/talent/getaway_artist">getaway artist</Link> rogue talent before choosing this talent.</p>
</>};
const _hide_in_plain_sight = {title: "Hide in Plain Sight", topLink: ["Advanced Rogue Talents","ability/advanced_rogue_talents"], jsx: <><h2 id="talent-hide_in_plain_sight-hide-in-plain-sight-ex">Hide in Plain Sight (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 71</Link><br/>A rogue with this talent can select a single terrain from the ranger's <Link to="/ability/favored_terrain">favored terrain</Link> list. She is a master at hiding in that terrain, and while within that terrain, she can use the <Link to="/skill/stealth">Stealth</Link> skill to hide, even while being observed. A rogue may take this advanced talent more than once, each time selecting a different terrain from the favored terrain list.</p>
</>};
const _master_of_disguise = {title: "Master of Disguise", topLink: ["Advanced Rogue Talents","ability/advanced_rogue_talents"], jsx: <><h2 id="talent-master_of_disguise-master-of-disguise-ex">Master of Disguise (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 132</Link><br/><strong>Rogue Only:</strong> Once per day, a rogue with this talent gains a +10 bonus on a single Disguise check.</p>
</>};
const _master_tricks = {title: "Master Tricks", topLink: ["Advanced Rogue Talents","ability/advanced_rogue_talents"], jsx: <><h2 id="talent-master_tricks-master-tricks">Master Tricks</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 71</Link><br/>The rogue can select a ninja trick from the list of <Link to="/ability/master_tricks">master tricks</Link> in place of a rogue talent. The rogue cannot select a ninja trick that has the same name as a rogue talent. The rogue can choose but cannot use tricks that require ki points, unless she has a ki pool.</p>
</>};
const _greater_multitalented = {title: "Greater Multitalented", topLink: ["Advanced Rogue Talents","ability/advanced_rogue_talents"], jsx: <><h2 id="talent-greater_multitalented-greater-multitalented-ex">Greater Multitalented (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 24</Link><br/><strong>Unchained Rogue Only:</strong> A rogue with this talent can use the multitalented rogue talent to gain additional uses of advanced talents. A rogue must have the <Link to="/talent/multitalented">multitalented</Link> talent to select this talent.</p>
</>};
const _pierce_the_darkness = {title: "Pierce the Darkness", topLink: ["Advanced Rogue Talents","ability/advanced_rogue_talents"], jsx: <><h2 id="talent-pierce_the_darkness-pierce-the-darkness-ex">Pierce the Darkness (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_streets">Heroes of the Streets pg. 26</Link><br/>The rogue can extend her senses of hearing and smell in darkness or when blinded. She gains <Link to="/umr/blindsense">blindsense</Link> out to a range of 5 feet, but only against creatures concealed by darkness or her own blindness. She still suffers the normal miss chance for attacking creatures with <Link to="/rule/concealment">concealment</Link>.</p>
</>};
const _rumormonger = {title: "Rumormonger", topLink: ["Advanced Rogue Talents","ability/advanced_rogue_talents"], jsx: <><h2 id="talent-rumormonger-rumormonger-ex">Rumormonger (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 71</Link><br/>A rogue with this talent can attempt to spread a rumor though a small town or larger settlement by making a Bluff check. She can do so a number of times per week equal to her Charisma modifier (minimum 0). The DC is based on the size of the settlement, and it takes a week for the rumor to propagate through the settlement. If the check succeeds, the rumor is practically accepted as fact within the community; succeeding by 5 or more over the DC decreases the time it takes the rumor to propagate by 1d4 days. A failed check means the rumor failed to gain traction, while failing by 5 or more causes the opposite of the rumor or some other competing theory involving the rumor's subject to take hold.</p>
<ScrollContainer id="talent-rumormonger--table-0"><table>
<thead>
<tr>
<th>Community Size</th>
<th>DC</th>
</tr>
</thead>
<tbody><tr>
<td>Small town</td>
<td>18</td>
</tr>
<tr>
<td>Large town</td>
<td>20</td>
</tr>
<tr>
<td>Small city</td>
<td>25</td>
</tr>
<tr>
<td>Large city</td>
<td>30</td>
</tr>
<tr>
<td>Metropolis</td>
<td>35</td>
</tr>
</tbody></table></ScrollContainer>
</>};
const _see_in_darkness = {title: "See in Darkness", topLink: ["Advanced Rogue Talents","ability/advanced_rogue_talents"], jsx: <><h2 id="talent-see_in_darkness-see-in-darkness-su">See in Darkness (Su)</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_shadows">Blood of Shadows pg. 9</Link><br/>The rogue gains the <Link to="/umr/see_in_darkness">see in darkness</Link> ability. A rogue must have darkvision before choosing this talent.</p>
</>};
const _skill_mastery = {title: "Skill Mastery", topLink: ["Advanced Rogue Talents","ability/advanced_rogue_talents"], jsx: <><h2 id="talent-skill_mastery-skill-mastery">Skill Mastery</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 70</Link>, <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 24</Link><br/><strong>Rogue Version:</strong> The rogue becomes so confident in the use of certain skills that she can use them reliably even under adverse conditions.</p>
<p>Upon gaining this ability, she selects a number of skills equal to 3 + her Intelligence modifier. When making a skill check with one of these skills, she may take 10 even if stress and distractions would normally prevent her from doing so. A rogue may gain this special ability multiple times, selecting additional skills for skill mastery to apply to each time.</p>
<p><strong>Unchained Rogue Version:</strong> The rogue becomes so confident in the use of certain skills that she can use them reliably even under adverse conditions. The rogue selects a number of skills equal to her Intelligence modifier. When making a skill check with one of the selected skills (or any of the skills selected through the rogue's edge class feature), she can take 10 even if stress and distractions would normally prevent her from doing so. A rogue can gain this special ability multiple times, selecting additional skills for skill mastery to apply to each time.</p>
</>};
const _stalker_talent = {title: "Stalker Talent", topLink: ["Advanced Rogue Talents","ability/advanced_rogue_talents"], jsx: <><h2 id="talent-stalker_talent-stalker-talent">Stalker Talent</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_intrigue">Ultimate Intrigue pg. 44</Link><br/>The rogue can select a <Link to="/ability/vigilante_talents">vigilante talent</Link>. For the purposes of selecting and using this talent, she counts as a 10th-level <Link to="/class/vigilante">vigilante</Link> with the stalker specialization, regardless of her actual rogue level. Her sneak attack counts as a hidden strike with reduced damage for the purpose of determining the effects of her vigilante talent, which means, among other things, that she can't apply any of the <em>hidden strike talents</em> to her sneak attacks.</p>
</>};
const _stony_skin = {title: "Stony Skin", topLink: ["Advanced Rogue Talents","ability/advanced_rogue_talents"], jsx: <><h2 id="talent-stony_skin-stony-skin-ex">Stony Skin (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/elemental_masters_handbook">Elemental Master's Handbook pg. 9</Link><br/>A rogue with this talent gains DR 2/adamantine. A rogue can select this talent up to three times; each additional time the rogue selects this talent, the DR granted by this talent increases by 1.</p>
</>};
const _greater_terrain_mastery = {title: "Greater Terrain Mastery", topLink: ["Advanced Rogue Talents","ability/advanced_rogue_talents"], jsx: <><h2 id="talent-greater_terrain_mastery-greater-terrain-mastery-ex">Greater Terrain Mastery (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 24</Link><br/><strong>Unchained Rogue Only:</strong> A rogue with this talent can select a single <Link to="/ability/favored_terrain">favored terrain</Link>. Her bonuses in that terrain increase to +4. At 13th level and 18th level, they increase by an additional +2 (to a maximum of +8). A rogue must have the <Link to="/talent/terrain_mastery">terrain mastery</Link> talent to select this advanced talent.</p>
</>};
const _thoughtful_reexamining = {title: "Thoughtful Reexamining", topLink: ["Advanced Rogue Talents","ability/advanced_rogue_talents"], jsx: <><h2 id="talent-thoughtful_reexamining-thoughtful-reexamining-ex">Thoughtful Reexamining (Ex)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 132</Link><br/><strong>Rogue Only:</strong> Once per day, a rogue with this talent can reroll a Knowledge, Sense Motive, or Perception skill check to try to gain new or better information from the roll. This reroll can be made any time during the same day as the original check.</p>
</>};
const _unlock_ki = {title: "Unlock Ki", topLink: ["Advanced Rogue Talents","ability/advanced_rogue_talents"], jsx: <><h2 id="talent-unlock_ki-unlock-ki-su">Unlock Ki (Su)</h2>
<p><strong>Sources</strong> <Link to="/source/magic_tactics_toolbox">Magic Tactics Toolbox pg. 27</Link><br/>A rogue with this advanced talent increases the number of points in the ki pool that she gains from the <Link to="/talent/ki_pool">ki pool</Link> rogue talent to be equal to 1/2 her rogue level + her highest mental ability score modifier (Intelligence, Wisdom, or Charisma). In addition, she can spend 2 points from her ki pool as a swift action to gain the skill unlocks for one skill of her choice as appropriate for her number of ranks in that skill. This benefit lasts for 1 minute. The rogue must have a ki pool before selecting this advanced talent.</p>
</>};
